/** Show `.app` as soon as routing is ready — do not wait for the rest of this ~24k-line module. */
function dismissBootSplash() {
  try {
    document.body.classList.remove("booting");
  } catch {}
}
try {
  window.addEventListener("error", dismissBootSplash);
  window.addEventListener("unhandledrejection", dismissBootSplash);
  setTimeout(dismissBootSplash, 3500);
} catch {}

/** UUID allowlist from `/api/public-config` (env `NABAD_CERTIFIED_USER_IDS`)
 *  — interim gate for the Profile "Verified Nabad Creator" badge until
 *  `profiles.sound_certified` is live in Supabase. */
let _nabadCertifiedUserIds = new Set();

/** Verified badges are gated by `profiles.sound_certified` or the optional UUID allowlist only. */
const INTERIM_ALWAYS_SHOW_PUBLIC_PROFILE_VERIFIED = false;
/** Founder account: the badge must remain stable even if env config/profile flags arrive late. */
const NABAD_FOUNDER_USERNAMES = new Set([
  "samy_foun",
  "samy_founder",
  "samy_naoum",
  "samynaoum",
  "saminaoum2022",
]);
const NABAD_FOUNDER_EMAIL_HINTS = ["samynaoum", "saminaoum2022"];

function normalizedBadgeUsername(raw) {
  return String(raw || "").trim().replace(/^@/, "").toLowerCase();
}

function isFounderBadgeUsername(raw) {
  const handle = normalizedBadgeUsername(raw);
  return Boolean(handle && NABAD_FOUNDER_USERNAMES.has(handle));
}

function isFounderBadgeEmail(raw) {
  const email = String(raw || "").trim().toLowerCase();
  if (!email || !email.includes("@")) return false;
  const local = email.split("@")[0] || "";
  return NABAD_FOUNDER_EMAIL_HINTS.some((hint) => local === hint || local.startsWith(`${hint}.`) || local.startsWith(`${hint}_`));
}

/**
 * Capacitor only wires native plugins after JS calls registerPlugin().
 * Our app has no bundle step that imports @capacitor/browser — without this,
 * Plugins.Browser is missing and Google OAuth never opens on iOS.
 * Web stubs mirror the official plugins (safe no-ops / window.open).
 */
(() => {
  try {
    const cap = typeof window !== "undefined" ? window.Capacitor : null;
    if (!cap?.registerPlugin) return;
    if (!cap.Plugins?.Browser) {
      cap.registerPlugin("Browser", {
        web: () => ({
          async open(options) {
            const url = options?.url;
            if (url) window.open(url, options?.windowName || "_blank");
          },
          async close() {},
        }),
      });
    }
    if (!cap.Plugins?.App) {
      cap.registerPlugin("App", {
        web: () => ({
          async addListener() {
            return { remove: async () => {} };
          },
          async removeAllListeners() {},
        }),
      });
    }
    if (!cap.Plugins?.NowPlaying) {
      cap.registerPlugin("NowPlaying", {
        web: () => ({
          async update() {},
          async clear() {},
          async addListener() {
            return { remove: async () => {} };
          },
        }),
      });
    }
    // On iOS/Android, never register Preferences with a localStorage web stub
    // before the native bridge loads — that was wiping sessions on force-quit.
    const isNative = Boolean(cap.isNativePlatform?.());
    if (!isNative && !cap.Plugins?.Preferences) {
      cap.registerPlugin("Preferences", {
        web: () => ({
          async get({ key }) {
            return { value: localStorage.getItem(key) };
          },
          async set({ key, value }) {
            if (value == null) localStorage.removeItem(key);
            else localStorage.setItem(key, value);
          },
          async remove({ key }) {
            localStorage.removeItem(key);
          },
        }),
      });
    }
    if (!isNative && !cap.Plugins?.AuthVault) {
      cap.registerPlugin("AuthVault", {
        web: () => ({
          async get() {
            return { value: null };
          },
          async set() {},
          async remove() {},
        }),
      });
    }
    if (!cap.Plugins?.Filesystem) {
      cap.registerPlugin("Filesystem");
    }
  } catch {
    /* Already registered elsewhere */
  }
})();

if (typeof window !== "undefined") {
  window.addEventListener("nabad-auth-injected", () => {
    try {
      invalidateAuthBoot();
      void ensureAuthBoot({ force: true }).then(() => {
        try {
          scheduleApplyRoute();
        } catch {}
      });
    } catch {}
  });
}

initLockScreenNowPlaying({
  getAudio: () => {
    const hub = hubAudio && !hubAudio.paused && !hubAudio.ended;
    const lib = playerEl && !playerEl.paused && !playerEl.ended;
    if (hub && !lib) return hubAudio;
    if (lib && !hub) return playerEl;
    if (hub && lib) {
      try {
        if ((hubAudio.currentTime || 0) >= (playerEl.currentTime || 0)) return hubAudio;
      } catch {}
      return playerEl;
    }
    return hubAudio || playerEl || null;
  },
  getMeta: () => hubNowMeta,
  getDuration: (audio) => {
    try {
      return getAudioDuration(audio);
    } catch {
      return Number(audio?.duration) || 0;
    }
  },
  onPlay: () => {
    const a = getMiniPlayerAudio() || hubAudio || playerEl;
    if (a) void a.play();
    try {
      renderHubNowPlaying();
    } catch {}
    syncLockScreenNowPlaying({ force: true });
  },
  onPause: () => {
    const a = getMiniPlayerAudio() || hubAudio || playerEl;
    if (a) a.pause();
    try {
      renderHubNowPlaying();
    } catch {}
    syncLockScreenNowPlaying({ force: true });
  },
  onToggle: () => {
    const a = getMiniPlayerAudio() || hubAudio || playerEl;
    if (!a) return;
    if (a.paused || a.ended) void a.play();
    else a.pause();
    try {
      renderHubNowPlaying();
    } catch {}
    syncLockScreenNowPlaying({ force: true });
  },
  onNext: () => {
    if (miniSource?.type === "discover_playlist" && _discoverPlaylistQueue?.length) {
      void playNextDiscoverPlaylistTrack(currentPlayerTrackRef?.url, { manual: true });
      return;
    }
    if (miniSource?.type === "discover_feed" && _discoveryFeedTracks?.length) {
      void playRandomDiscoveryFeedTrack(currentPlayerTrackRef?.url);
      return;
    }
    if (miniSource?.type === "public_profile_lib" && _userPublicFeedTracks?.length) {
      void playRandomUserPublicFeedTrack(currentPlayerTrackRef?.url);
    }
  },
});

