/** Headers for native/web calls to Vercel `/api/*` (optional deployment-protection bypass). */
function getApiFetchHeaders(extra = {}) {
  const headers = { ...(extra || {}) };
  const bypass = getVercelProtectionBypass();
  if (bypass) headers["x-vercel-protection-bypass"] = bypass;
  return headers;
}

function apiFetch(path, opts = {}) {
  const headers = getApiFetchHeaders(opts.headers || {});
  return fetch(apiUrl(path), { ...opts, headers });
}

function applyPublicConfigPayload(d) {
  let rawUrl = String(d?.supabaseUrl || "").trim();
  rawUrl = rawUrl.replace(/\/+$/, "");
  rawUrl = rawUrl.replace(/\/rest\/v1$/i, "");
  rawUrl = rawUrl.replace(/\/auth\/v1$/i, "");
  SUPABASE_URL = rawUrl;
  SUPABASE_ANON_KEY = String(d?.supabaseAnonKey || "");
  const ids = Array.isArray(d?.nabadCertifiedUserIds) ? d.nabadCertifiedUserIds : [];
  _nabadCertifiedUserIds = new Set(
    ids.map((x) => String(x || "").trim()).filter(Boolean),
  );
  if (SUPABASE_URL) addPreconnectHint(SUPABASE_URL);
}

function loadPublicConfigFromCache() {
  try {
    const raw = localStorage.getItem(PUBLIC_CONFIG_CACHE_KEY);
    if (!raw) return false;
    const parsed = JSON.parse(raw);
    applyPublicConfigPayload(parsed);
    if (isNativeShell() && parsed?.apiBase) setResolvedApiBase(parsed.apiBase);
    else _resolvedApiBase = "";
    return Boolean(SUPABASE_URL && SUPABASE_ANON_KEY);
  } catch {
    return false;
  }
}

function isNativeShell() {
  try {
    return Boolean(window.Capacitor?.isNativePlatform?.());
  } catch {
    return false;
  }
}

function applyClientEnvBootstrap() {
  try {
    const env = window.__NABAD_CLIENT_ENV__;
    if (!env || typeof env !== "object") return false;
    applyPublicConfigPayload(env);
    const bypass = String(env.vercelProtectionBypass || "").trim();
    if (bypass) {
      try {
        window.__VERCEL_PROTECTION_BYPASS__ = bypass;
      } catch {}
    }
    if (isNativeShell() && env.apiBase) setResolvedApiBase(env.apiBase);
    else _resolvedApiBase = "";
    return Boolean(SUPABASE_URL && SUPABASE_ANON_KEY);
  } catch {
    return false;
  }
}

/** Shown on Friends only when Supabase settings are missing (Friends reads feed via Supabase, not /api). */
function friendsFeedBlockedMessage() {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
    const m = loginConfigFailureMessage();
    return m || "App settings could not load. Hard-refresh or check your connection.";
  }
  return "";
}

async function ensureFriendsFeedPrerequisites() {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
    await loadPublicConfig();
  }
  if (getSupabaseAuthToken() && !authSession?.user?.id) {
    try {
      await refreshAuthStateFromSupabase();
    } catch {}
  }
  return !friendsFeedBlockedMessage();
}

let SUPABASE_URL = "";
let SUPABASE_ANON_KEY = "";
let lastHubUpdateAt = 0;
function relativeTime(ts) {
  if (!ts) return "—";
  const diff = Date.now() - Number(ts || 0);
  if (diff < 10_000) return "just now";
  const min = Math.floor(diff / 60_000);
  if (min < 1) return "just now";
  if (min < 60) return `${min}m ago`;
  const hr = Math.floor(min / 60);
  if (hr < 24) return `${hr}h ago`;
  const d = Math.floor(hr / 24);
  return `${d}d ago`;
}
function renderHubUpdatedAt() {
  if (!els.hubUpdatedAt) return;
  const relative = relativeTime(lastHubUpdateAt);
  els.hubUpdatedAt.textContent = `Updated: ${relative}`;
  if (els.hubSyncInfo) {
    els.hubSyncInfo.classList.remove("ok", "warn", "wait");
    if (hubLastSyncOk) {
      els.hubSyncInfo.classList.add("ok");
      els.hubSyncInfo.textContent = `● Live • rows ${hubLastSyncRows}`;
    } else if (hubLastSyncError) {
      els.hubSyncInfo.classList.add("warn");
      els.hubSyncInfo.textContent = `● Retrying • ${hubLastSyncError}`;
    } else {
      els.hubSyncInfo.classList.add("wait");
      els.hubSyncInfo.textContent = "● Waiting…";
    }
  }
}
function updateEnvironmentBadge() {
  if (!els.envBadge) return;
  els.envBadge.textContent = `Build ${APP_BUILD}`;
}
function cachePublicConfigPayload(apiBase = "") {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY) return;
  try {
    localStorage.setItem(
      PUBLIC_CONFIG_CACHE_KEY,
      JSON.stringify({
        supabaseUrl: SUPABASE_URL,
        supabaseAnonKey: SUPABASE_ANON_KEY,
        nabadCertifiedUserIds: [..._nabadCertifiedUserIds],
        apiBase: String(apiBase || _resolvedApiBase || API_BASE || "").trim(),
      }),
    );
  } catch {}
}

/** Fetch `/api/public-config` from one origin (relative on web). */
async function fetchPublicConfigOnce(base) {
  const url = base
    ? `${String(base).replace(/\/$/, "")}/api/public-config`
    : "/api/public-config";
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 6000);
  try {
    const r = await fetch(url, { signal: ctrl.signal, headers: getApiFetchHeaders() });
    lastPublicConfigStatus = r.status;
    const d = await r.json().catch(() => ({}));
    if (d?.supabaseUrl && d?.supabaseAnonKey) {
      applyPublicConfigPayload(d);
      setResolvedApiBase(base);
      cachePublicConfigPayload(base);
      return true;
    }
    if (r.status === 403) {
      lastPublicConfigError = "403_deployment_protection";
      const recovered = loadPublicConfigFromCache() || applyClientEnvBootstrap();
      if (recovered) {
        lastPublicConfigStatus = 0;
        lastPublicConfigError = "";
      }
      return recovered;
    }
    if (r.ok) {
      applyPublicConfigPayload(d);
      setResolvedApiBase(base);
      cachePublicConfigPayload(base);
    }
    return Boolean(SUPABASE_URL && SUPABASE_ANON_KEY);
  } finally {
    clearTimeout(timer);
  }
}

/** Native needs the same Vercel host for /api/social as for public-config (Discover uses Supabase only). */
async function ensureNativeApiBaseResolved() {
  if (!isNativeShell()) return true;
  if (_resolvedApiBase) {
    try {
      if (await fetchPublicConfigOnce(_resolvedApiBase)) return true;
    } catch {}
  }
  for (const base of nativeApiBaseCandidates()) {
    try {
      if (await fetchPublicConfigOnce(base)) return true;
    } catch {}
  }
  return Boolean(_resolvedApiBase);
}

async function loadPublicConfig() {
  applyClientEnvBootstrap();
  let ok = Boolean(SUPABASE_URL && SUPABASE_ANON_KEY);
  if (!ok) ok = loadPublicConfigFromCache();

  if (!ok) {
    lastPublicConfigStatus = 0;
    lastPublicConfigError = "";
    const bases = isNativeShell() ? nativeApiBaseCandidates() : [""];
    for (const base of bases) {
      try {
        if (await fetchPublicConfigOnce(base)) {
          ok = true;
          break;
        }
      } catch (e) {
        lastPublicConfigError = e?.name === "AbortError" ? "timeout" : "network";
      }
    }
    if (!ok) ok = loadPublicConfigFromCache();
  }

  if (ok && isNativeShell()) {
    await ensureNativeApiBaseResolved();
  }
  return Boolean(SUPABASE_URL && SUPABASE_ANON_KEY);
}

function loginConfigFailureMessage() {
  if (loadPublicConfigFromCache() || applyClientEnvBootstrap()) return "";
  if (lastPublicConfigError === "403_deployment_protection") {
    return "Vercel blocked API (403). Turn off Deployment Protection for Production, or set VERCEL_PROTECTION_BYPASS and redeploy.";
  }
  return "Could not load login settings. Check your connection and try again.";
}
const _addedPreconnects = new Set();
function addPreconnectHint(url) {
  try {
    const u = new URL(url, location.origin);
    const origin = `${u.protocol}//${u.host}`;
    if (_addedPreconnects.has(origin)) return;
    _addedPreconnects.add(origin);
    const link = document.createElement("link");
    link.rel = "preconnect";
    link.href = origin;
    link.crossOrigin = "anonymous";
    document.head.appendChild(link);
  } catch {}
}
let _lastHapticAt = 0;
let _hapticBurstWindowStart = 0;
let _hapticBurstCount = 0;
const HAPTIC_MIN_GAP_MS = 280;
const HAPTIC_BURST_MAX = 6;
const HAPTIC_BURST_WINDOW_MS = 2500;

function haptic(kind = "light") {
  const now = Date.now();
  if (now - _lastHapticAt < HAPTIC_MIN_GAP_MS) return;
  if (!_hapticBurstWindowStart || now - _hapticBurstWindowStart > HAPTIC_BURST_WINDOW_MS) {
    _hapticBurstWindowStart = now;
    _hapticBurstCount = 0;
  }
  if (_hapticBurstCount >= HAPTIC_BURST_MAX) return;
  _hapticBurstCount += 1;
  _lastHapticAt = now;
  try {
    const cap = window?.Capacitor;
    const isNative = Boolean(
      cap?.isNativePlatform?.() ||
      cap?.getPlatform?.() === "ios" ||
      cap?.getPlatform?.() === "android"
    );
    const capHaptics = cap?.Plugins?.Haptics;
    if (capHaptics) {
      if (kind === "success") {
        void capHaptics.notification({ type: "SUCCESS" });
      } else if (kind === "impact") {
        void capHaptics.impact({ style: "HEAVY" });
      } else {
        void capHaptics.impact({ style: "LIGHT" });
      }
      return;
    }
    if (isNative) return;
    if (!("vibrate" in navigator)) return;
    if (kind === "success") navigator.vibrate([8, 24, 12]);
    else if (kind === "impact") navigator.vibrate(12);
    else navigator.vibrate(6);
  } catch {}
}
function showLikeBurst() {
  if (!els.likeBurst) return;
  const el = els.likeBurst;
  el.style.display = "";
  el.classList.remove("show");
  void el.offsetWidth;
  el.classList.add("show");
  setTimeout(() => {
    el.classList.remove("show");
    el.style.display = "none";
  }, 620);
}

/* ------------------------------------------------------------------
 *  Tap-active-tab to refresh
 *
 *  Twitter/Instagram pattern: when the user is already ON a route and
 *  taps that route's bottom-bar tab, scroll to top and re-run the
 *  same data-layer refresh the route would do. The first tap from any
 *  other route still just navigates — only when source === destination
 *  do we intercept and refresh. Create is intentionally not listed so
 *  a half-typed prompt is never re-fetched / wiped.
 *
 *  Visual: the active tab's icon does a single-revolution spin while
 *  the refresh runs (CSS `.isRefreshing` class on the tab anchor).
 * ----------------------------------------------------------------- */
/* Each action FIRES its refreshes and returns immediately. The spin
 * animation is a *visual* confirmation, not a network wait — Profile
 * in particular was painting the icon for 20+ seconds whenever the
 * cellular round-trip to /auth/v1/user dragged, which read as the
 * app hanging. The actual data continues loading in the background;
 * the UI updates reactively as each promise resolves.
 *
 * Profile intentionally drops refreshAuthStateFromSupabase() — that
 * call only re-validates the JWT and the user object barely ever
 * changes between taps. Keeping credits + my-hub-posts gives the
 * user the two values that actually move (balance + new shares).  */
const TAB_REFRESH_ACTIONS = {
  ...(HUB_FEATURE_ENABLED
    ? {
      hub() {
        void Promise.resolve(refreshHubFromSupabase()).catch((e) => console.warn("[tabRefresh/hub]", e));
      },
    }
    : {}),
  challenges() {
    try {
      renderHomeDesk();
      const page = document.querySelector('[data-route="challenges"]');
      if (page) void refreshHomeDeskJoinCounts(page);
    } catch (e) { console.warn("[tabRefresh/challenges]", e); }
  },
  discover() {
    try {
      void refreshDiscoverFeed();
    } catch (e) { console.warn("[tabRefresh/discover]", e); }
  },
  friends() {
    try {
      syncFollowingComposeUi();
      void refreshDiscoveryFollowingFeed();
    } catch (e) { console.warn("[tabRefresh/friends]", e); }
  },
  mentor() {
    resetMentorSession();
  },
  profile() {
    void Promise.resolve(refreshMyCredits({ silent: true })).catch(() => {});
    void Promise.resolve(refreshMyHubPostsFast({ force: true })).catch(() => {});
    void Promise.resolve(refreshNotificationsUnreadBadge({ force: true })).catch(() => {});
    renderProfileSongs();
    void Promise.resolve(reconcileLibraryFromCloud({ force: true }))
      .catch((e) => console.warn("[tabRefresh/profile-songs]", e));
  },
};

let _tabRefreshSpinTimer = 0;

function triggerTabRefresh(route) {
  const fn = TAB_REFRESH_ACTIONS[route];
  if (!fn) return;
  try { fn(); } catch (e) { console.warn("[tabRefresh]", e); }
  try { window.scrollTo({ top: 0, behavior: "smooth" }); } catch {}
  // Fixed visual: a single, satisfying rotation regardless of network.
  // 900ms ≈ one rotation of the CSS animation, plus a tiny breath.
  const tabEl = document.querySelector(`.mobileTabbar a[data-route-link="${route}"]`);
  if (!tabEl) return;
  tabEl.classList.add("isRefreshing");
  if (_tabRefreshSpinTimer) clearTimeout(_tabRefreshSpinTimer);
  _tabRefreshSpinTimer = setTimeout(() => {
    tabEl.classList.remove("isRefreshing");
    _tabRefreshSpinTimer = 0;
  }, 900);
}

function attachTabRefresh() {
  const tabs = document.querySelectorAll(".mobileTabbar a[data-route-link]");
  tabs.forEach((a) => {
    a.addEventListener("click", (e) => {
      const route = a.getAttribute("data-route-link") || "";
      if (!TAB_REFRESH_ACTIONS[route]) return;
      const current = document.body.getAttribute("data-route") || "";
      if (route !== current) return;
      // Already on this route → treat the tap as a refresh trigger.
      // Stop the link navigation so the hashchange handler doesn't
      // also fire (which would re-render the route from scratch and
      // cause a double-flash on top of our scoped refresh).
      e.preventDefault();
      e.stopPropagation();
      void triggerTabRefresh(route);
    });
  });
}

