async function refreshDiscoverChallengeSpotlight() {
  const wrap = document.getElementById("discoverChallengeSpotlight");
  const rail = document.getElementById("discoverChallengeSpotlightRail");
  const countEl = document.getElementById("discoverChallengeSpotlightCount");
  if (!wrap || !rail) return;
  try {
    const rows = await supabaseFetchDiscoveryPublicSongs(80);
    const entries = rows.filter((t) => challengeMetaForTrack(t) && String(t.url || "").trim());
    if (!entries.length) {
      wrap.hidden = true;
      rail.innerHTML = "";
      if (countEl) countEl.textContent = "";
      return;
    }
    const profMap = await fetchProfilesByUserIdsMap(entries.map((t) => t.userId));
    const spotlight = entries.slice(0, 5);
    wrap.hidden = false;
    if (countEl) countEl.textContent = `${entries.length} this week`;
    rail.innerHTML = spotlight.map((track) => {
      const prof = track.userId ? profMap.get(track.userId) : null;
      const handle = String(prof?.username || "").trim();
      const artSafe = trackCoverArtForFeed(track);
      const title = String(track.title || "Song").trim();
      return `
        <button type="button" class="discoverChallengeSpotCard" data-challenge-entry-play="${encodeURIComponent(track.url || "")}" data-challenge-entry-title="${encodeURIComponent(title)}" data-challenge-entry-art="${encodeURIComponent(artSafe)}" data-challenge-entry-by="${encodeURIComponent(handle ? `@${handle}` : "Creator")}" data-play-song-id="${encodeURIComponent(track.id || "")}" data-play-owner-id="${encodeURIComponent(track.userId || "")}" data-play-task-id="${encodeURIComponent(track.taskId || "")}" data-play-audio-id="${encodeURIComponent(track.audioId || "")}">
          <span class="discoverChallengeSpotArt"><img src="${escapeHtml(artSafe)}" alt="" loading="lazy" decoding="async" /></span>
          <span class="discoverChallengeSpotMeta">
            <strong>${escapeHtml(title)}</strong>
            ${handle ? `<small>@${escapeHtml(handle)}</small>` : ""}
          </span>
        </button>`;
    }).join("");
  } catch {
    wrap.hidden = true;
    rail.innerHTML = "";
  }
}

function bindHomeDeskOnce(page) {
  if (!page || page.dataset.boundHomeDesk === "1") return;
  page.dataset.boundHomeDesk = "1";
  wireHomeDeskSegOnce();
  page.addEventListener("click", (e) => {
    const cont = e.target?.closest?.("#homeDeskContinueBtn");
    if (cont && page.contains(cont)) {
      haptic("light");
      continueIdeaFromLibraryTrack(_homeDeskContinueTrack);
      return;
    }
    const echoLearn = e.target?.closest?.("[data-home-echo-learn]");
    if (echoLearn && page.contains(echoLearn)) {
      haptic("light");
      try {
        location.hash = "#/friends";
      } catch {}
      scheduleApplyRoute();
      return;
    }
    const echoRecord = e.target?.closest?.("[data-home-echo-record]");
    if (echoRecord && page.contains(echoRecord)) {
      haptic("light");
      if (!authSession?.user?.id) {
        try {
          location.hash = "#/profile";
        } catch {}
        scheduleApplyRoute();
        setStatus("Sign in to record an Echo.");
        return;
      }
      try {
        location.hash = "#/friends";
      } catch {}
      scheduleApplyRoute();
      setTimeout(() => {
        try {
          openEchoFromCreateChooser();
        } catch {}
      }, 120);
      return;
    }
    const ideaBtn = e.target?.closest?.("[data-discovery-idea]");
    if (ideaBtn && page.contains(ideaBtn)) {
      const idea = [...DISCOVERY_IDEAS, ...DISCOVERY_QUICK_IDEAS].find(
        (row) => String(row.id) === String(ideaBtn.getAttribute("data-discovery-idea") || ""),
      );
      if (idea) {
        haptic("light");
        applyDiscoveryIdeaToCreate(idea);
      }
      return;
    }
    const sparkBtn = e.target?.closest?.("[data-challenge-start]");
    if (sparkBtn && page.contains(sparkBtn)) {
      applyChallengeStartById(String(sparkBtn.getAttribute("data-challenge-start") || ""), null);
    }
  });
}

async function refreshHomeDeskJoinCounts(page) {
  if (!page) return;
  try {
    const rows = await supabaseFetchDiscoveryPublicSongs(80);
    const entries = rows.filter((t) => challengeMetaForTrack(t));
    const counts = new Map();
    for (const track of entries) {
      const challenge = challengeMetaForTrack(track);
      const id = String(challenge?.id || "").trim();
      if (!id) continue;
      counts.set(id, (counts.get(id) || 0) + 1);
    }
    page.querySelectorAll("[data-challenge-count]").forEach((el) => {
      const id = String(el.getAttribute("data-challenge-count") || "").trim();
      const n = counts.get(id) || 0;
      el.textContent = `${n} joined`;
    });
  } catch {}
}

function renderHomeDesk() {
  const page = document.querySelector('[data-route="challenges"]');
  if (!page) return;
  bindHomeDeskOnce(page);
  _homeSeg = readHomeSeg();
  syncHomeSegUi();
  const greeting = document.getElementById("homeDeskGreeting");
  if (greeting) greeting.textContent = `Hey, ${homeDeskGreetingName()}`;
  renderHomeDeskQuickStarts();
  renderHomeDeskSparksDeck();
  renderHomeDeskContinue();
  syncHomeMakeSegUi();
  void refreshHomeDeskJoinCounts(page);
  if (typeof page._refreshChallengeEntries === "function") void page._refreshChallengeEntries();
}

function bindChallengesPageOnce() {
  const page = document.querySelector('[data-route="challenges"]');
  if (!page || page.dataset.boundChallenges === "1") return;
  page.dataset.boundChallenges = "1";
  const challenges = new Map(CHALLENGE_IDEAS.map((idea) => [String(idea.id), idea]));
  const occasionRail = document.getElementById("challengeOccasionRail");
  const genreRail = document.getElementById("challengeGenreRail");
  const languageRail = document.getElementById("challengeLanguageRail");
  const presetGrid = document.getElementById("challengePresetGrid");
  const nameInput = document.getElementById("challengePersonName");
  let selectedOccasion = CHALLENGE_OCCASIONS[0]?.id || "";
  let selectedGenre = CHALLENGE_GENRES[0]?.id || "";
  let selectedLanguage = CHALLENGE_LANGUAGES[0]?.id || "auto";
  const selected = (list, id) => list.find((item) => item.id === id) || list[0] || null;
  const nameForPrompt = () => String(nameInput?.value || "").trim();
  const requireChallengeName = () => {
    if (_homeMakeSeg !== "personal") return true;
    if (nameForPrompt()) return true;
    try { nameInput?.focus?.({ preventScroll: true }); } catch {}
    try { nameInput?.scrollIntoView?.({ behavior: "smooth", block: "center" }); } catch {}
    try { nameInput?.closest?.(".challengeNameField")?.classList?.add?.("isRequired"); } catch {}
    try { showToast("Add their name for a personal dedication", { icon: "✍", durationMs: 2600 }); } catch {}
    return false;
  };
  const buildChallengeLyricPrompt = (occasion, genre, language, person, variant) => {
    const take = variant === "dance"
      ? "Make it danceable with a repeatable hook."
      : variant === "cinematic"
        ? "Make it cinematic, emotional, and chorus-led."
        : "Make it catchy, personal, and easy to sing.";
    const languageHint = language?.id && language.id !== "auto"
      ? language.prompt
      : "Use the natural language for this style.";
    return [
      `Write lyrics for ${person}: ${occasion.angle}.`,
      take,
      languageHint,
      "Use verse and chorus sections.",
    ].join("\n");
  };
  const buildPresetIdea = (occasion, genre, variant = "anthem") => {
    const language = selected(CHALLENGE_LANGUAGES, selectedLanguage);
    const person = nameForPrompt() || "someone special";
    const variantLabel = variant === "dance"
      ? "Dance version"
      : variant === "cinematic"
        ? "Cinematic version"
        : "Signature version";
    const title = `${occasion.title} - ${variantLabel}`;
    const tempoHint = variant === "dance"
      ? "112-124 bpm, energetic but polished"
      : variant === "cinematic"
        ? "slow cinematic intro into a memorable chorus"
        : "mid-tempo, polished, emotional but catchy";
    const challengeBrief = `Challenge brief: ${occasion.angle}. Dedicated to ${person}. Keep the lyrics personal and avoid generic lines.`;
    const lyricPrompt = buildChallengeLyricPrompt(occasion, genre, language, person, variant);
    return {
      id: `occasion:${occasion.id}:${genre.id}:${variant}`,
      title,
      style: `${genre.style}, ${tempoHint}, personalized for ${person}. ${challengeBrief}`,
      prompt: lyricPrompt,
      lyrics: lyricPrompt,
      dialect: "",
      dialectHint: "",
      tags: [...(occasion.tags || []), genre.label],
      challenge: {
        id: `occasion:${occasion.id}:${genre.id}`,
        title: `${occasion.label} ${genre.label}`,
        type: "occasion",
        occasion: occasion.label,
        genre: genre.label,
        language: language?.label || "Auto",
        languageId: language?.id || "auto",
        dialect: "",
        dialectHint: "",
        personName: person,
        variant,
      },
    };
  };
  const renderFilters = () => {
    if (occasionRail) {
      occasionRail.innerHTML = CHALLENGE_OCCASIONS.map((o) => `
        <button type="button" class="challengeFilterChip${o.id === selectedOccasion ? " active" : ""}" data-challenge-occasion="${escapeHtml(o.id)}" aria-pressed="${o.id === selectedOccasion ? "true" : "false"}">${escapeHtml(o.label)}</button>
      `).join("");
    }
    if (genreRail) {
      genreRail.innerHTML = CHALLENGE_GENRES.map((g) => `
        <button type="button" class="challengeFilterChip challengeFilterChip--genre${g.id === selectedGenre ? " active" : ""}" data-challenge-genre="${escapeHtml(g.id)}" aria-pressed="${g.id === selectedGenre ? "true" : "false"}">${escapeHtml(g.label)}</button>
      `).join("");
    }
    if (languageRail) {
      languageRail.innerHTML = CHALLENGE_LANGUAGES.map((l) => `
        <button type="button" class="challengeFilterChip challengeFilterChip--language${l.id === selectedLanguage ? " active" : ""}" data-challenge-language="${escapeHtml(l.id)}" aria-pressed="${l.id === selectedLanguage ? "true" : "false"}">${escapeHtml(l.label)}</button>
      `).join("");
    }
  };
  const renderPresets = () => {
    if (!presetGrid) return;
    const occasion = selected(CHALLENGE_OCCASIONS, selectedOccasion);
    const genre = selected(CHALLENGE_GENRES, selectedGenre);
    if (!occasion || !genre) return;
    const variants = ["anthem", "dance", "cinematic"].map((variant) => buildPresetIdea(occasion, genre, variant));
    presetGrid.innerHTML = variants.map((preset) => `
      <article class="challengePresetCard">
        <span class="challengePresetChip">${escapeHtml(genre.label)}</span>
        <h3>${escapeHtml(preset.title)}</h3>
        <p>${escapeHtml(preset.prompt)}</p>
        <div class="challengePresetTags">${(preset.tags || []).slice(0, 3).map((tag) => `<span>${escapeHtml(tag)}</span>`).join("")}</div>
        <button type="button" data-challenge-preset="${escapeHtml(preset.id)}">Create this</button>
      </article>
    `).join("");
  };
  const renderPresetLab = () => {
    renderFilters();
    renderPresets();
  };
  const updateChallengeJoinCounts = (entries = []) => {
    const counts = new Map();
    for (const track of entries) {
      const challenge = challengeMetaForTrack(track);
      const id = String(challenge?.id || "").trim();
      if (!id) continue;
      counts.set(id, (counts.get(id) || 0) + 1);
    }
    document.querySelectorAll("[data-challenge-count]").forEach((el) => {
      const id = String(el.getAttribute("data-challenge-count") || "").trim();
      const n = counts.get(id) || 0;
      el.textContent = `${n} joined`;
    });
  };
  const refreshChallengeEntries = async () => {
    const rows = await supabaseFetchDiscoveryPublicSongs(80);
    const entries = rows.filter((track) => challengeMetaForTrack(track));
    updateChallengeJoinCounts(entries);
    _challengeEntryTracks = entries.map((t) => ({
      ...t,
      songId: String(t.id || ""),
      ownerUserId: String(t.userId || ""),
    }));
    void refreshDiscoverChallengeSpotlight();
  };
  renderPresetLab();
  syncHomeMakeSegUi();
  page._refreshChallengeEntries = refreshChallengeEntries;
  void refreshChallengeEntries();
  renderHomeDesk();
  page.addEventListener("click", (e) => {
    const occCreate = e.target?.closest?.("[data-home-occasion-create]");
    if (occCreate && page.contains(occCreate)) {
      const occasion = selected(CHALLENGE_OCCASIONS, selectedOccasion);
      const genre = selected(CHALLENGE_GENRES, selectedGenre);
      if (!occasion || !genre) return;
      haptic("light");
      applyDiscoveryIdeaToCreate(buildPresetIdea(occasion, genre, "anthem"));
      return;
    }
    const segBtn = e.target?.closest?.("[data-home-make-seg]");
    if (segBtn && page.contains(segBtn)) {
      _homeMakeSeg = String(segBtn.getAttribute("data-home-make-seg") || "occasion");
      haptic("light");
      syncHomeMakeSegUi();
      return;
    }
    const occasionBtn = e.target?.closest?.("[data-challenge-occasion]");
    if (occasionBtn && page.contains(occasionBtn)) {
      selectedOccasion = String(occasionBtn.getAttribute("data-challenge-occasion") || selectedOccasion);
      haptic("light");
      renderPresetLab();
      return;
    }
    const genreBtn = e.target?.closest?.("[data-challenge-genre]");
    if (genreBtn && page.contains(genreBtn)) {
      selectedGenre = String(genreBtn.getAttribute("data-challenge-genre") || selectedGenre);
      haptic("light");
      renderPresetLab();
      return;
    }
    const languageBtn = e.target?.closest?.("[data-challenge-language]");
    if (languageBtn && page.contains(languageBtn)) {
      selectedLanguage = String(languageBtn.getAttribute("data-challenge-language") || selectedLanguage);
      haptic("light");
      renderPresetLab();
      return;
    }
    const presetBtn = e.target?.closest?.("[data-challenge-preset]");
    if (presetBtn && page.contains(presetBtn)) {
      if (!requireChallengeName()) return;
      const [, occasionId, genreId, variant] = String(presetBtn.getAttribute("data-challenge-preset") || "").split(":");
      const occasion = selected(CHALLENGE_OCCASIONS, occasionId);
      const genre = selected(CHALLENGE_GENRES, genreId);
      if (!occasion || !genre) return;
      haptic("light");
      applyDiscoveryIdeaToCreate(buildPresetIdea(occasion, genre, variant || "anthem"));
      return;
    }
    const btn = e.target?.closest?.("[data-challenge-start]");
    if (btn && page.contains(btn)) {
      applyChallengeStartById(String(btn.getAttribute("data-challenge-start") || ""), challenges);
    }
  });
  nameInput?.addEventListener?.("input", () => {
    try { nameInput.closest?.(".challengeNameField")?.classList?.remove?.("isRequired"); } catch {}
    renderPresets();
  });
}

function renderDiscoveryIdeasOnce() {
  const rail = document.getElementById("discoveryIdeasRail");
  const grid = document.getElementById("discoveryQuickGrid");
  const pane = document.getElementById("discoveryPaneIdeas");
  const searchToggle = document.getElementById("discoveryIdeasSearchToggle");
  const input = document.getElementById("searchInput");
  const titleEl = pane?.querySelector?.(".discoveryIdeasTitle");
  const leadEl = pane?.querySelector?.(".discoveryIdeasLead");
  if (!rail || !grid || rail.dataset.renderedIdeas === "1") return;
  rail.dataset.renderedIdeas = "1";
  const tagHtml = (tags) => (Array.isArray(tags) ? tags : [])
    .slice(0, 4)
    .map((tag) => `<span>${escapeHtml(tag)}</span>`)
    .join("");
  rail.innerHTML = DISCOVERY_IDEAS.map((idea, idx) => `
    <article class="discoveryIdeaCard discoveryIdeaCard--${escapeHtml(idea.tone || "violet")}" style="--i:${idx}">
      <div class="discoveryIdeaCardGlow" aria-hidden="true"></div>
      <div class="discoveryIdeaTop">
        <span class="discoveryIdeaKicker">${escapeHtml(idea.kicker || "Prompt")}</span>
        <span class="discoveryIdeaMeta">${escapeHtml(idea.time || "Fast")}</span>
      </div>
      <h3>${escapeHtml(idea.title)}</h3>
      <p>${escapeHtml(idea.prompt)}</p>
      <div class="discoveryIdeaTags">${tagHtml(idea.tags)}</div>
      <button type="button" class="discoveryIdeaStart" data-discovery-idea="${escapeHtml(idea.id)}">Start</button>
    </article>
  `).join("");
  grid.innerHTML = DISCOVERY_QUICK_IDEAS.map((idea) => `
    <button type="button" class="discoveryQuickIdea" data-discovery-idea="${escapeHtml(idea.id)}">
      <span>${escapeHtml(idea.title)}</span>
      <small>${tagHtml(idea.tags)}</small>
    </button>
  `).join("");
  const ideas = new Map([...DISCOVERY_IDEAS, ...DISCOVERY_QUICK_IDEAS].map((idea) => [String(idea.id), idea]));
  const handleClick = (e) => {
    const btn = e.target?.closest?.("[data-discovery-idea]");
    if (!btn) return;
    const idea = ideas.get(String(btn.getAttribute("data-discovery-idea") || ""));
    if (!idea) return;
    haptic("light");
    applyDiscoveryIdeaToCreate(idea);
  };
  rail.addEventListener("click", handleClick);
  grid.addEventListener("click", handleClick);
  if (pane && searchToggle && input) {
    const defaultTitle = titleEl?.textContent || "This Week's Sparks";
    const defaultLead = leadEl?.textContent || "Tiny challenges to get you making fast. Pick one, then bend it your way.";
    const openSearch = () => {
      pane.classList.add("isSearchOpen");
      searchToggle.setAttribute("aria-expanded", "true");
      searchToggle.setAttribute("aria-label", "Close ideas search");
      if (titleEl) titleEl.textContent = "Search ideas";
      if (leadEl) leadEl.textContent = "Find a birthday, hook, remix, or prompt template.";
      requestAnimationFrame(() => window.setTimeout(() => input.focus(), 40));
    };
    const closeSearch = () => {
      pane.classList.remove("isSearchOpen");
      searchToggle.setAttribute("aria-expanded", "false");
      searchToggle.setAttribute("aria-label", "Search ideas");
      if (titleEl) titleEl.textContent = defaultTitle;
      if (leadEl) leadEl.textContent = defaultLead;
      input.blur();
    };
    searchToggle.addEventListener("click", () => {
      haptic("light");
      if (pane.classList.contains("isSearchOpen")) {
        closeSearch();
      } else {
        openSearch();
      }
    });
    input.addEventListener("input", () => {
      if (String(input.value || "").trim() && !pane.classList.contains("isSearchOpen")) {
        openSearch();
      }
    });
  }
}

function openSearchRemixSheet(tpl) {
  const sheet = document.getElementById("searchRemixSheet");
  if (!sheet || !tpl) return;
  _searchActiveTemplate = tpl;
  const occ = document.getElementById("searchRemixOccasion");
  const title = document.getElementById("searchRemixTitle");
  const sub = document.getElementById("searchRemixSub");
  const nameInput = document.getElementById("searchRemixName");
  const cta = document.getElementById("searchRemixCta");
  const coverImg = document.getElementById("searchRemixCover");
  const previewBtn = document.getElementById("searchRemixPreviewBtn");
  const audio = document.getElementById("searchRemixPreviewAudio");
  const coverUrl = String(tpl.coverUrl || "").trim();
  const previewUrl = String(tpl.previewUrl || "").trim();
  if (coverImg) {
    if (coverUrl) {
      coverImg.hidden = false;
      coverImg.src = coverUrl;
    } else {
      try { coverImg.removeAttribute("src"); } catch {}
      coverImg.hidden = true;
    }
  }
  if (audio) {
    try { audio.pause(); } catch {}
    try { audio.currentTime = 0; } catch {}
    if (previewUrl) {
      audio.src = previewUrl;
    } else {
      try { audio.removeAttribute("src"); } catch {}
    }
  }
  if (previewBtn) {
    previewBtn.hidden = !previewUrl;
    previewBtn.disabled = !previewUrl;
    previewBtn.classList.remove("isPlaying");
  }
  if (occ) occ.textContent = tpl.occasion;
  if (title) title.textContent = tpl.title;
  if (sub) sub.textContent = tpl.sub;
  if (nameInput) {
    nameInput.value = "";
    nameInput.placeholder = "Sara";
    setTimeout(() => nameInput.focus(), 80);
  }
  if (cta) cta.disabled = false;
  sheet.hidden = false;
  requestAnimationFrame(() => sheet.classList.add("isOpen"));
}

function closeSearchRemixSheet() {
  const sheet = document.getElementById("searchRemixSheet");
  if (!sheet) return;
  sheet.classList.remove("isOpen");
  setTimeout(() => { sheet.hidden = true; }, 240);
  const audio = document.getElementById("searchRemixPreviewAudio");
  if (audio) {
    try { audio.pause(); } catch {}
    try { audio.currentTime = 0; } catch {}
  }
  const playBtn = document.getElementById("searchRemixPreviewBtn");
  if (playBtn) {
    playBtn.classList.remove("isPlaying");
    playBtn.hidden = false;
    playBtn.disabled = false;
  }
  _searchActiveTemplate = null;
}

function applyRemixTemplateToCreate(tpl, name) {
  if (!tpl) return;
  const cleanName = String(name || "").trim() || "you";
  const lyrics = String(tpl.lyrics || "").replaceAll("[name]", cleanName);
  const titleWithName = `${tpl.title} — for ${cleanName}`;
  if (els.sunoPrompt) els.sunoPrompt.value = lyrics;
  if (els.sunoStyle) els.sunoStyle.value = String(tpl.style || "");
  if (els.sunoTitle) els.sunoTitle.value = titleWithName;
  pendingSearchRemixMeta = {
    searchTemplateId: String(tpl.id || "").trim(),
    searchTemplateTitle: String(tpl.title || "").trim(),
    searchRemixPersonalizedFor: cleanName,
  };
  try { setStatus?.(`Loaded ${tpl.title} — tap Generate when ready.`); } catch {}
}

function initSearchPageOnce() {
  if (_searchInited) return;
  _searchInited = true;
  const input = document.getElementById("searchInput");
  const bar = input?.closest(".searchBar");
  const clearBtn = document.getElementById("searchInputClear");
  if (input) {
    input.addEventListener("input", () => {
      const v = input.value;
      if (bar) bar.classList.toggle("hasValue", Boolean(v));
      if (clearBtn) clearBtn.hidden = !v;
      runSearchQuery(v);
    });
    input.addEventListener("focus", stopSearchHintRotator);
    input.addEventListener("blur", () => { if (!input.value) startSearchHintRotator(); });
  }
  if (clearBtn) {
    clearBtn.addEventListener("click", () => {
      if (!input) return;
      input.value = "";
      if (bar) bar.classList.remove("hasValue");
      clearBtn.hidden = true;
      runSearchQuery("");
      input.focus();
    });
  }
  const sheet = document.getElementById("searchRemixSheet");
  if (sheet) {
    sheet.addEventListener("click", (e) => {
      const t = e.target;
      if (t && t instanceof HTMLElement && t.matches('[data-action="close-remix"]')) {
        closeSearchRemixSheet();
      }
    });
  }
  const cta = document.getElementById("searchRemixCta");
  if (cta) {
    cta.addEventListener("click", () => {
      const tpl = _searchActiveTemplate;
      const nameInput = document.getElementById("searchRemixName");
      const name = nameInput?.value || "";
      if (!tpl) return;
      applyRemixTemplateToCreate(tpl, name);
      closeSearchRemixSheet();
      location.hash = "#/generate";
      try { syncGenerateOrbVisibility?.(); } catch {}
    });
  }
  const previewBtn = document.getElementById("searchRemixPreviewBtn");
  const previewAudio = document.getElementById("searchRemixPreviewAudio");
  if (previewBtn && previewAudio) {
    previewAudio.addEventListener("ended", () => {
      previewBtn.classList.remove("isPlaying");
    });
    previewBtn.addEventListener("click", () => {
      const tpl = _searchActiveTemplate;
      const url = String(tpl?.previewUrl || "").trim();
      const audio = document.getElementById("searchRemixPreviewAudio");
      const btn = document.getElementById("searchRemixPreviewBtn");
      if (!url || !audio || !btn) {
        const cta = document.getElementById("searchRemixCta");
        if (!cta) return;
        cta.animate(
          [
            { transform: "translateX(0)" },
            { transform: "translateX(-3px)" },
            { transform: "translateX(3px)" },
            { transform: "translateX(0)" },
          ],
          { duration: 220, easing: "ease-out" },
        );
        return;
      }
      if (audio.paused) {
        void audio.play().then(() => btn.classList.add("isPlaying")).catch(() => {
          try {
            showToast("Could not play preview.", { icon: "♪", durationMs: 2800 });
          } catch {}
        });
      } else {
        try { audio.pause(); } catch {}
        btn.classList.remove("isPlaying");
      }
    });
  }
  runSearchQuery("");
}

function onEnterSearchRoute() {
  initSearchPageOnce();
  renderDiscoveryIdeasOnce();
  startSearchHintRotator();
  void refreshSearchTemplates().then(() => {
    const input = document.getElementById("searchInput");
    runSearchQuery(input?.value || "");
  });
}
function onLeaveSearchRoute() {
  stopSearchHintRotator();
  closeSearchRemixSheet();
}

