const CREATE_ENTRY_INTENT_KEY = "nabadai_create_entry_intent_v1";
const PENDING_CREATE_ACTION_KEY = "nabadai_pending_create_action_v1";

function setCreateEntryIntent(intent) {
  try {
    if (!intent) sessionStorage.removeItem(CREATE_ENTRY_INTENT_KEY);
    else sessionStorage.setItem(CREATE_ENTRY_INTENT_KEY, String(intent));
  } catch {}
}

function getCreateEntryIntent() {
  try { return String(sessionStorage.getItem(CREATE_ENTRY_INTENT_KEY) || "").trim(); } catch {}
  return "";
}

function setPendingCreateAction(action) {
  try {
    const kind = String(action || "").trim();
    if (!kind) sessionStorage.removeItem(PENDING_CREATE_ACTION_KEY);
    else sessionStorage.setItem(PENDING_CREATE_ACTION_KEY, kind);
  } catch {}
}

function getPendingCreateAction() {
  try { return String(sessionStorage.getItem(PENDING_CREATE_ACTION_KEY) || "").trim(); } catch {}
  return "";
}

function finishPostAuthNavigation() {
  const pending = getPendingCreateAction();
  setPendingCreateAction("");
  if (pending === "song" || pending === "status" || pending === "echo") {
    window.setTimeout(() => {
      try { navigateFromCreateChooser(pending); } catch {}
    }, 80);
    return;
  }
  const target = shouldSkipIntroOrOnboardingRoute() ? "challenges" : "intro";
  try { location.hash = `#/${target}`; } catch {}
  syncRoutePanelVisibility(target);
  safeApplyRoute();
}

function requireAuthForCreate(onAuthed, pendingAction = "") {
  if (authSession?.user?.id) {
    try { onAuthed?.(); } catch {}
    return true;
  }
  setPendingCreateAction(pendingAction);
  closeCreateChooserSheet();
  try { showToast("Sign in to create", { icon: "👤", durationMs: 2400 }); } catch {}
  try { location.hash = "#/auth"; } catch {}
  return false;
}

let _createChooserNavLock = false;

/** Single router for Create chooser → existing engines (no new API routes). */
function navigateFromCreateChooser(action) {
  const kind = String(action || "").trim();
  if (!kind) return;
  if (_createChooserNavLock) return;
  if (!requireAuthForCreate(() => navigateFromCreateChooser(kind), kind)) return;

  _createChooserNavLock = true;

  try {
    if (kind === "echo") {
      openEchoFromCreateChooser();
      closeCreateChooserSheet({ immediate: true });
      return;
    }

    closeCreateChooserSheet({ immediate: true });

    if (kind === "song") {
      setCreateEntryIntent("song");
      const onGenerate = String(location.hash || "") === "#/generate";
      if (!onGenerate) try { location.hash = "#/generate"; } catch {}
      else scheduleApplyRoute();
      window.setTimeout(() => {
        try { if (typeof setActiveCreateTab === "function") setActiveCreateTab("lyrics"); } catch {}
        try { els.sunoPrompt?.focus?.({ preventScroll: true }); } catch {}
      }, 100);
      return;
    }

    if (kind === "status") {
      openFriendsForStatusCompose();
      return;
    }
  } finally {
    window.setTimeout(() => {
      _createChooserNavLock = false;
    }, 320);
  }
}

function openFriendsForStatusCompose() {
  setCreateEntryIntent("");
  _friendsStatusComposePending = true;
  _followComposeType = "update";
  try { syncFollowingComposeUi(); } catch {}
  const onFriends = String(location.hash || "") === "#/friends";
  if (!onFriends) {
    try { location.hash = "#/friends"; } catch {}
  } else {
    enterFriendsRoute();
  }
}

function wireCreateChooserSheetOnce() {
  const sheet = document.getElementById("createChooserSheet");
  if (!sheet || sheet.dataset.wiredCreateChooserSheet) return;
  sheet.dataset.wiredCreateChooserSheet = "1";
  sheet.addEventListener("click", (e) => {
    const dismiss = e.target?.closest?.("[data-create-chooser-dismiss]");
    if (dismiss) {
      e.preventDefault();
      e.stopPropagation();
      closeCreateChooserSheet();
      return;
    }
    const btn = e.target?.closest?.("[data-create-chooser]");
    if (!btn || !sheet.contains(btn)) return;
    e.preventDefault();
    e.stopPropagation();
    navigateFromCreateChooser(btn.getAttribute("data-create-chooser"));
  });
}

