function syncFollowingComposeUi() {
  const compose = document.getElementById("discoveryFollowingCompose");
  const input = document.getElementById("followComposeInput");
  const postBtn = document.getElementById("followComposePost");
  const countEl = document.getElementById("followComposeCount");
  const promptEl = document.getElementById("followComposePrompt");
  const signHint = document.getElementById("followComposeSignInHint");
  const mic = document.getElementById("followComposeMic");
  const signedIn = Boolean(authSession?.user?.id);
  const hasText = Boolean(String(input?.value || "").trim());
  const hasVoice = Boolean(statusVoiceBlob?.size);
  const recording = statusVoiceRecState === "recording";
  if (compose) compose.classList.toggle("isSignedOut", !signedIn);
  if (signHint) signHint.hidden = signedIn;
  if (input) input.disabled = !signedIn || recording;
  if (mic) mic.disabled = !signedIn;
  if (postBtn) postBtn.disabled = !signedIn || (!hasText && !hasVoice) || recording;
  const meta = followingComposeMeta(_followComposeType);
  if (promptEl) {
    promptEl.textContent = hasVoice || recording ? "Voice drop — add an optional caption" : meta.prompt;
  }
  if (input && !input.matches(":focus")) {
    input.placeholder = hasVoice ? "Optional caption…" : meta.placeholder;
  }
  document.querySelectorAll("[data-follow-compose-type]").forEach((chip) => {
    const on = chip.getAttribute("data-follow-compose-type") === _followComposeType;
    chip.classList.toggle("isActive", on);
    chip.setAttribute("aria-selected", on ? "true" : "false");
  });
  const len = String(input?.value || "").length;
  if (countEl) countEl.textContent = `${len} / 320`;
  syncStatusVoiceComposeUi();
}

function bindFollowingComposeOnce() {
  if (_followComposeBound) return;
  _followComposeBound = true;
  const input = document.getElementById("followComposeInput");
  const postBtn = document.getElementById("followComposePost");
  document.querySelectorAll("[data-follow-compose-type]").forEach((chip) => {
    chip.addEventListener("click", () => {
      _followComposeType = String(chip.getAttribute("data-follow-compose-type") || "update");
      haptic("light");
      syncFollowingComposeUi();
      try { input?.focus?.({ preventScroll: true }); } catch {}
    });
  });
  input?.addEventListener("input", () => syncFollowingComposeUi());
  document.getElementById("followComposeMic")?.addEventListener("click", () => {
    toggleStatusVoiceMicTap();
  });
  document.getElementById("followComposeVoicePlay")?.addEventListener("click", () => {
    void previewStatusVoiceCompose();
  });
  document.getElementById("followComposeVoiceDiscard")?.addEventListener("click", () => {
    resetStatusVoiceCompose();
    syncFollowingComposeUi();
    try {
      haptic("light");
    } catch {}
  });
  postBtn?.addEventListener("click", async () => {
    if (!authSession?.user?.id) {
      closeFriendsComposeSheet();
      try { showToast("Sign in to post", { icon: "👤", durationMs: 2400 }); } catch {}
      location.hash = "#/profile";
      return;
    }
    const text = String(input?.value || "").trim();
    const hasVoice = Boolean(statusVoiceBlob?.size);
    if (!text && !hasVoice) return;
    const prevPostLabel = postBtn.textContent || "Post";
    postBtn.disabled = true;
    postBtn.textContent = hasVoice ? "Uploading…" : "Posting…";
    try {
      let audioUrl = "";
      let durationMs = 0;
      let waveformPeaks = [];
      if (hasVoice) {
        const uploaded = await uploadStatusVoiceBlob(statusVoiceBlob);
        audioUrl = uploaded.url;
        durationMs = statusVoiceDurationMs;
        waveformPeaks = statusVoicePeaks.length ? statusVoicePeaks : await computeStatusWaveformPeaks(statusVoiceBlob);
      }
      const res = await postFriendsStatus(
        {
          postType: _followComposeType,
          body: text,
          audioUrl,
          durationMs,
          waveformPeaks,
        },
        { timeoutMs: hasVoice ? 45000 : 12000 },
      );
      const fallbackBody = text || (hasVoice ? STATUS_VOICE_DEFAULT_BODY : "");
      _friendsOwnPostPin = normalizeFriendsOwnPost(res?.post, fallbackBody, _followComposeType);
      if (input) input.value = "";
      resetStatusVoiceCompose();
      closeFriendsComposeSheet();
      haptic("success");
      try { showToast("Posted — followers will see it", { icon: "✓", durationMs: 2200 }); } catch {}
      await prependFriendsOwnPost(_friendsOwnPostPin);
      if (
        (document.body.getAttribute("data-route") || "") === "profile" &&
        _profileSongsSegment === "activities"
      ) {
        void renderProfileActivities();
      }
    } catch (e) {
      haptic("error");
      try {
        showToast(
          e?.message || "Could not post — run social_status_posts_voice.sql and status_audio_storage.sql in Supabase",
          { icon: "!", durationMs: 3200 },
        );
      } catch {}
    } finally {
      postBtn.textContent = prevPostLabel;
      syncFollowingComposeUi();
    }
  });
  wireStatusVoicePlaybackOnce();
  syncFollowingComposeUi();
}

function followingActivityPlayAttrs(t, profMap, byLine) {
  const artSafe = trackCoverArtForFeed(t);
  const rawTitle = String(t.title || "Untitled");
  const encUrl = encodeURIComponent(String(t.url || ""));
  const encTitle = encodeURIComponent(rawTitle);
  const encBy = encodeURIComponent(byLine || "");
  const encArt = encodeURIComponent(artSafe);
  const encSongId = encodeURIComponent(String(t.id || t.songId || ""));
  const encOwnerId = encodeURIComponent(String(t.userId || ""));
  const encTaskId = encodeURIComponent(String(t.taskId || ""));
  const encAudioId = encodeURIComponent(String(t.audioId || ""));
  const encReleaseCaption = encodeURIComponent(releaseCaptionForTrack(t));
  const playData = `data-play-song-id="${encSongId}" data-play-owner-id="${encOwnerId}" data-play-task-id="${encTaskId}" data-play-audio-id="${encAudioId}" data-play-release-caption="${encReleaseCaption}"`;
  return { artSafe, rawTitle, encUrl, encTitle, encBy, encArt, playData };
}

/**
 * X-style actions row: Reply / Like / Plays.
 *
 * Like + Reply are wired to the social API on tap. Counts and the
 * viewer's liked-state are loaded lazily after the feed renders by
 * `hydrateFeedSocialStatsForFeed()`, which then calls
 * `applyFeedSocialStatsToDom()` to fill in the counts and the filled
 * heart for items the viewer already liked.
 *
 * `kind` here is "music" or "status" (UI kind). The DB target kind is
 * derived: music → "song", status → "status".
 */
function followActActionsRowHtml({ kind, targetId, targetUserId, plays } = {}) {
  const safeId = escapeHtml(String(targetId || ""));
  const safeUid = escapeHtml(String(targetUserId || ""));
  const safeKind = escapeHtml(String(kind || ""));
  const targetKind = kind === "music" ? "song" : kind === "status" ? "status" : (kind || "");
  const safeTargetKind = escapeHtml(targetKind);
  const playsBlock = kind === "music" && Number.isFinite(Number(plays)) && Number(plays) > 0
    ? `<span class="followActAct followActAct--stat" data-friends-act="plays" aria-label="${escapeHtml(formatStatCount(plays))} plays">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M5 4v16l14-8L5 4Z"/></svg>
        <span class="followActActCount">${escapeHtml(formatStatCount(plays))}</span>
      </span>`
    : `<span class="followActAct followActAct--stat" aria-hidden="true"></span>`;
  return `
    <div class="followActActions" data-friends-act-row="1" data-friends-act-kind="${safeKind}" data-friends-act-target-kind="${safeTargetKind}" data-friends-act-id="${safeId}" data-friends-act-uid="${safeUid}">
      <button type="button" class="followActAct" data-friends-act="reply" aria-label="Reply">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M4 5h16v10H8l-4 4V5Z"/></svg>
        <span class="followActActCount" data-friends-act-count="reply"></span>
      </button>
      <button type="button" class="followActAct" data-friends-act="like" aria-label="Like" aria-pressed="false">
        <svg class="followActActIco" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 21s-7-4.5-9.5-9A5.5 5.5 0 0 1 12 6a5.5 5.5 0 0 1 9.5 6c-2.5 4.5-9.5 9-9.5 9Z"/></svg>
        <span class="followActActCount" data-friends-act-count="like"></span>
      </button>
      ${playsBlock}
    </div>`;
}

/* ---------------------------------------------------------------------
 * Feed social stats (likes + replies) — batched fetch, optimistic UI
 * ------------------------------------------------------------------- */

// Map<"kind:id", { likeCount, liked, replyCount }> — survives feed snapshot
// hydrations so when we re-paint from a cached snapshot the counts are
// re-applied immediately.
const _feedSocialStats = new Map();
let _feedSocialStatsGen = 0;
let _feedSocialStatsLastFetchAt = 0;

function feedSocialStatsKey(targetKind, targetId) {
  return `${targetKind}:${targetId}`;
}

function getFeedSocialStat(targetKind, targetId) {
  return (
    _feedSocialStats.get(feedSocialStatsKey(targetKind, targetId)) ||
    { likeCount: 0, liked: false, replyCount: 0 }
  );
}

function setFeedSocialStat(targetKind, targetId, partial) {
  const key = feedSocialStatsKey(targetKind, targetId);
  const prev = _feedSocialStats.get(key) || { likeCount: 0, liked: false, replyCount: 0 };
  _feedSocialStats.set(key, { ...prev, ...partial });
  return _feedSocialStats.get(key);
}

/**
 * Render the current stats into all `.followActActions` rows inside the
 * given scope. Safe to call multiple times — idempotent.
 */
function applyFeedSocialStatsToDom(scope) {
  const root = scope || document;
  const rows = root.querySelectorAll(".followActActions[data-friends-act-row]");
  rows.forEach((row) => {
    const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
    const targetId = row.getAttribute("data-friends-act-id") || "";
    if (!targetKind || !targetId) return;
    const stat = getFeedSocialStat(targetKind, targetId);
    const likeBtn = row.querySelector('[data-friends-act="like"]');
    const likeCount = row.querySelector('[data-friends-act-count="like"]');
    const replyCount = row.querySelector('[data-friends-act-count="reply"]');
    if (likeBtn) {
      likeBtn.classList.toggle("isLiked", Boolean(stat.liked));
      likeBtn.setAttribute("aria-pressed", stat.liked ? "true" : "false");
    }
    if (likeCount) likeCount.textContent = stat.likeCount > 0 ? formatStatCount(stat.likeCount) : "";
    if (replyCount) replyCount.textContent = stat.replyCount > 0 ? formatStatCount(stat.replyCount) : "";
  });
}

/**
 * Collect ids in the current feed DOM, then batch-fetch stats from the
 * API and write them into the local map + DOM. Only the freshest call
 * mutates state (gen guard).
 */
async function hydrateFeedSocialStatsForFeed(listEl) {
  if (!listEl) return;
  const rows = listEl.querySelectorAll(".followActActions[data-friends-act-row]");
  const songIds = [];
  const statusIds = [];
  rows.forEach((row) => {
    const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
    const targetId = row.getAttribute("data-friends-act-id") || "";
    if (!targetKind || !targetId) return;
    if (targetKind === "song") songIds.push(targetId);
    else if (targetKind === "status") statusIds.push(targetId);
  });
  if (!songIds.length && !statusIds.length) return;
  const gen = ++_feedSocialStatsGen;
  try {
    const params = new URLSearchParams();
    params.set("type", "feed_social_stats");
    if (songIds.length) params.set("song_ids", songIds.join(","));
    if (statusIds.length) params.set("status_ids", statusIds.join(","));
    const data = await socialApi(`/api/social?${params.toString()}`);
    if (gen !== _feedSocialStatsGen) return;
    if (data?.likes) {
      for (const [kind, bucket] of Object.entries(data.likes)) {
        for (const [id, info] of Object.entries(bucket || {})) {
          setFeedSocialStat(kind, id, {
            likeCount: Number(info?.count) || 0,
            liked: Boolean(info?.liked),
          });
        }
      }
    }
    if (data?.replies) {
      for (const [kind, bucket] of Object.entries(data.replies)) {
        for (const [id, info] of Object.entries(bucket || {})) {
          setFeedSocialStat(kind, id, {
            replyCount: Number(info?.count) || 0,
          });
        }
      }
    }
    _feedSocialStatsLastFetchAt = Date.now();
    applyFeedSocialStatsToDom(listEl);
  } catch {
    /* swallow — counts stay empty, taps still work */
  }
}

function followingActivityRowHtml(t, profMap, idx, opts = {}) {
  const xstyle = Boolean(opts && opts.xstyle);
  const type = followingActivityTypeForTrack(t);
  const prof = t.userId ? profMap.get(t.userId) : null;
  const handle = String(prof?.username || "").trim();
  const byLine = handle ? `@${handle}` : "Creator";
  const rawTitle = String(t.title || "Untitled");
  const safeTitle = escapeHtml(rawTitle);
  const remixOf = remixAttributionForTrack(t);
  const challenge = challengeMetaForTrack(t);
  const { artSafe, encUrl, encTitle, encBy, encArt, playData } = followingActivityPlayAttrs(t, profMap, byLine);
  const avatarRaw = String(prof?.avatar || "").trim();
  const avatarSrc = avatarRaw ? normalizeProfileAvatarForImg(avatarRaw) : "";
  const initials = (handle || "U").replace(/^@/, "").slice(0, 2).toUpperCase();
  const profileHref = handle ? `#/u/${encodeURIComponent(handle)}` : "#";
  const when = relativeTime(t.ts);
  const plays = Number(t.playCount);
  const caption = releaseCaptionForTrack(t);
  const captionHtml = caption
    ? `<p class="followActCaption">${escapeHtml(caption)}</p>`
    : "";
  const verbHtml = followingActivityBodyHtml(type, rawTitle, remixOf, challenge);
  const subtitle = handle ? `@${handle}` : "Musician";
  if (xstyle) {
    return `
      <article class="followAct followAct--music followAct--xstyle" data-follow-act="${type}" style="--i:${idx}" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData}>
        <a class="followActAvatar" href="${escapeHtml(profileHref)}" data-route-link="user" data-avatar-user-id="${escapeHtml(String(t.userId || ""))}" aria-label="${handle ? `@${escapeHtml(handle)} profile` : "Profile"}">
          <span class="followActAvatarRing" aria-hidden="true"></span>
          ${avatarSrc
            ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="40" height="40" decoding="async" loading="lazy" />`
            : `<span class="followActAvatarFallback">${escapeHtml(initials)}</span>`}
        </a>
        <div class="followActColumn">
          <div class="followActMeta">
            <a class="followActUserLink" href="${escapeHtml(profileHref)}" data-route-link="user">${handle ? `<strong class="followActUser">@${escapeHtml(handle)}</strong>` : `<strong class="followActUser">A musician</strong>`}</a>
            <span class="followActMetaDot" aria-hidden="true">·</span>
            <span class="followActWhen">${escapeHtml(when)}</span>
            <span class="followActMetaDot" aria-hidden="true">·</span>
            ${followingActivityBadgeHtml("music", type)}
          </div>
          <div class="followActContent">
            <p class="followActHead">${verbHtml}</p>
            ${captionHtml}
          </div>
          <button type="button" class="followActQuoteCard" data-user-lib-play="1" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData} aria-label="Play ${safeTitle}">
            <span class="followActQuoteArt">
              <img class="followActQuoteImg" src="${escapeHtml(artSafe)}" alt="" decoding="async" loading="lazy" />
              <span class="followActQuotePlay" aria-hidden="true">
                <svg viewBox="0 0 24 24" width="14" height="14" aria-hidden="true"><path d="M5 4v16l14-8L5 4Z" fill="currentColor"/></svg>
              </span>
            </span>
            <span class="followActQuoteBody">
              <span class="followActQuoteTitle">${safeTitle}</span>
              <span class="followActQuoteSub">${escapeHtml(subtitle)}</span>
            </span>
          </button>
          ${followActActionsRowHtml({ kind: "music", targetId: t.id, targetUserId: t.userId, plays })}
        </div>
      </article>`;
  }
  const playFoot = Number.isFinite(plays) && plays > 0
    ? `<div class="followActFoot"><span class="followActFootStat">${escapeHtml(formatStatCount(plays))} ${plays === 1 ? "play" : "plays"}</span></div>`
    : "";
  const who = handle
    ? `<strong class="followActUser">@${escapeHtml(handle)}</strong>`
    : `<strong class="followActUser">A musician</strong>`;
  return `
    <article class="followAct followAct--music" data-follow-act="${type}" style="--i:${idx}" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData}>
      <div class="followActTop">
        <a class="followActAvatar" href="${escapeHtml(profileHref)}" data-route-link="user" data-avatar-user-id="${escapeHtml(String(t.userId || ""))}" aria-label="${handle ? `@${escapeHtml(handle)} profile` : "Profile"}">
          <span class="followActAvatarRing" aria-hidden="true"></span>
          ${avatarSrc
            ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="40" height="40" decoding="async" loading="lazy" />`
            : `<span class="followActAvatarFallback">${escapeHtml(initials)}</span>`}
        </a>
        <div class="followActTopText">
          <div class="followActWhoLine">
            <a class="followActUserLink" href="${escapeHtml(profileHref)}" data-route-link="user">${who}</a>
            <span class="followActWhen">${escapeHtml(when)}</span>
          </div>
          ${followingActivityBadgeHtml("music", type)}
        </div>
      </div>
      <div class="followActContent">
        <p class="followActHead">${followingActivityBodyHtml(type, rawTitle, remixOf, challenge)}</p>
        ${captionHtml}
      </div>
      <button type="button" class="followActMedia" data-user-lib-play="1" data-user-lib-url="${encUrl}" data-user-lib-title="${encTitle}" data-user-lib-art="${encArt}" data-discovery-by="${encBy}" ${playData} aria-label="Play ${safeTitle}">
        <img class="followActMediaImg" src="${escapeHtml(artSafe)}" alt="" decoding="async" loading="lazy" />
        <span class="followActMediaPlay" aria-hidden="true">▶</span>
      </button>
      ${playFoot}
    </article>`;
}

function followingActivitySkeletonHtml() {
  // Mix two music rows (with quoted track card) and two status rows (text only),
  // matching the X-style layout the real feed renders. Avatar on the left,
  // meta + body + actions stacked in the right column, divider between rows.
  const musicRow = (i) => `
    <article class="followAct followAct--xstyle followAct--music followAct--skel" style="--i:${i}" aria-hidden="true">
      <span class="followActAvatar followActSkel followActSkelAvatar"></span>
      <div class="followActColumn">
        <div class="followActMeta">
          <span class="followActSkel followActSkelMetaLine"></span>
        </div>
        <div class="followActContent">
          <span class="followActSkel followActSkelHeadLine"></span>
          <span class="followActSkel followActSkelHeadLine short"></span>
        </div>
        <div class="followActQuoteCard followActQuoteCard--skel">
          <span class="followActQuoteArt followActSkel"></span>
          <span class="followActQuoteBody">
            <span class="followActSkel followActSkelQuoteTitle"></span>
            <span class="followActSkel followActSkelQuoteSub"></span>
          </span>
        </div>
        <div class="followActActions">
          <span class="followActAct followActAct--skel followActSkel"></span>
          <span class="followActAct followActAct--skel followActSkel"></span>
          <span class="followActAct followActAct--skel followActSkel"></span>
        </div>
      </div>
    </article>`;
  const statusRow = (i) => `
    <article class="followAct followAct--xstyle followAct--status followAct--skel" style="--i:${i}" aria-hidden="true">
      <span class="followActAvatar followActSkel followActSkelAvatar"></span>
      <div class="followActColumn">
        <div class="followActMeta">
          <span class="followActSkel followActSkelMetaLine"></span>
        </div>
        <div class="followActContent">
          <span class="followActSkel followActSkelTextLine"></span>
          <span class="followActSkel followActSkelTextLine"></span>
          <span class="followActSkel followActSkelTextLine short"></span>
        </div>
        <div class="followActActions">
          <span class="followActAct followActAct--skel followActSkel"></span>
          <span class="followActAct followActAct--skel followActSkel"></span>
          <span class="followActAct followActAct--skel followActSkel"></span>
        </div>
      </div>
    </article>`;
  return [musicRow(0), statusRow(1), musicRow(2), statusRow(3)].join("");
}

async function fetchFollowingEmptySuggestCreators(limit = 3, excludeUserIds = []) {
  const out = [];
  const blocked = new Set(
    [...(excludeUserIds || []), authSession?.user?.id]
      .map((u) => String(u || "").trim())
      .filter(Boolean),
  );
  try {
    const rows = await supabaseFetchDiscoveryPublicSongs(48);
    const profMap = await fetchProfilesByUserIdsMap(rows.map((r) => r.userId));
    const seen = new Set();
    for (const t of rows) {
      const uid = String(t.userId || "").trim();
      if (!uid || seen.has(uid) || blocked.has(uid)) continue;
      seen.add(uid);
      const prof = profMap.get(uid);
      const handle = String(prof?.username || "").trim();
      if (!handle) continue;
      const avatar = normalizeProfileAvatarForImg(String(prof?.avatar || "").trim());
      out.push({ userId: uid, handle, avatar });
      if (out.length >= limit) break;
    }
  } catch {}
  return out;
}

/**
 * End-of-list "Who to follow" — X-style vertical list with 3 rows visible
 * and a "Show more" link that routes to Discover for the long tail.
 */
function whoToFollowSectionHtml(creators) {
  if (!Array.isArray(creators) || !creators.length) return "";
  const rows = creators.slice(0, 3).map((c) => {
    const handle = String(c.handle || "").trim();
    const userId = String(c.userId || "").trim();
    if (!handle || !userId) return "";
    const safeHandle = escapeHtml(handle);
    const safeUid = escapeHtml(userId);
    const initials = handle.replace(/^@/, "").slice(0, 2).toUpperCase();
    const href = `#/u/${encodeURIComponent(handle)}`;
    const avatarHtml = c.avatar
      ? `<img src="${escapeHtml(c.avatar)}" alt="" width="44" height="44" decoding="async" loading="lazy" />`
      : `<span class="friendsWtfFallback">${escapeHtml(initials)}</span>`;
    return `
      <li class="friendsWtfRow" data-friends-wtf-row="${safeUid}">
        <a class="friendsWtfAvatar" href="${escapeHtml(href)}" data-route-link="user" aria-label="@${safeHandle} profile">
          ${avatarHtml}
        </a>
        <a class="friendsWtfText" href="${escapeHtml(href)}" data-route-link="user">
          <strong class="friendsWtfName">@${safeHandle}</strong>
          <span class="friendsWtfSub">Musician on Nabadai</span>
        </a>
        <button type="button" class="friendsWtfFollow" data-friends-follow="${safeUid}" data-friends-follow-handle="${safeHandle}">Follow</button>
      </li>`;
  }).filter(Boolean).join("");
  if (!rows) return "";
  return `
    <section class="friendsWhoToFollow" aria-label="Who to follow">
      <h3 class="friendsWtfTitle">Who to follow</h3>
      <ul class="friendsWtfList" role="list">${rows}</ul>
      <a class="friendsWtfMore" href="#/discover" data-route-link="discover">Show more</a>
    </section>`;
}

/**
 * Toggle the like state on a feed item. Optimistic UI: flip the heart
 * and bump the count immediately, POST in the background, revert if the
 * call fails. Bound to both Friends and Profile activity click handlers.
 */
async function handleFeedLikeTap(btn) {
  const row = btn.closest(".followActActions");
  if (!row) return;
  const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
  const targetId = row.getAttribute("data-friends-act-id") || "";
  if (!targetKind || !targetId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to like posts.");
    location.hash = "#/auth";
    return;
  }
  if (btn.dataset.likeBusy === "1") return;
  btn.dataset.likeBusy = "1";

  const prev = getFeedSocialStat(targetKind, targetId);
  const nextLiked = !prev.liked;
  const nextCount = Math.max(0, prev.likeCount + (nextLiked ? 1 : -1));
  setFeedSocialStat(targetKind, targetId, { liked: nextLiked, likeCount: nextCount });
  // Apply optimistic UI to every row that displays this target.
  document.querySelectorAll(
    `.followActActions[data-friends-act-target-kind="${targetKind}"][data-friends-act-id="${targetId}"]`,
  ).forEach((r) => applyFeedSocialStatsToDom(r.parentElement || r));
  try { haptic("light"); } catch {}
  btn.classList.add("isPulse");
  window.setTimeout(() => btn.classList.remove("isPulse"), 320);

  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: nextLiked ? "like" : "unlike",
        targetKind,
        targetId,
      }),
    });
    if (data?.ok && typeof data.count === "number") {
      setFeedSocialStat(targetKind, targetId, {
        liked: Boolean(data.liked),
        likeCount: Number(data.count) || 0,
      });
      applyFeedSocialStatsToDom(document);
    }
  } catch (e) {
    // Revert.
    setFeedSocialStat(targetKind, targetId, { liked: prev.liked, likeCount: prev.likeCount });
    applyFeedSocialStatsToDom(document);
    showToast(e?.message || "Could not update like.");
  } finally {
    delete btn.dataset.likeBusy;
  }
}

/* ---------------------------------------------------------------------
 * Feed Reply sheet (X-style thread modal)
 * ------------------------------------------------------------------- */

let _feedReplyContext = null;
let _feedReplyBound = false;

function openFeedReplySheetFromButton(btn) {
  const row = btn.closest(".followActActions");
  const article = btn.closest(".followAct");
  if (!row || !article) return;
  const targetKind = row.getAttribute("data-friends-act-target-kind") || "";
  const targetId = row.getAttribute("data-friends-act-id") || "";
  if (!targetKind || !targetId) return;

  const handleEl = article.querySelector(".followActUser");
  const handle = String(handleEl?.textContent || "").trim();
  const subEl =
    article.querySelector(".followActStatusText") ||
    article.querySelector(".followActQuoteTitle") ||
    article.querySelector(".followActHead");
  const sub = String(subEl?.textContent || "").trim();

  openFeedReplySheet({
    targetKind,
    targetId,
    handle,
    sub,
  });
}

function openFeedReplySheet({ targetKind, targetId, handle, sub }) {
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to reply.");
    location.hash = "#/auth";
    return;
  }
  const sheet = document.getElementById("feedReplySheet");
  if (!sheet) return;
  bindFeedReplySheetOnce();
  _feedReplyContext = { targetKind, targetId };

  const header = document.getElementById("feedReplyHeader");
  const subEl = document.getElementById("feedReplySub");
  if (header) header.textContent = handle ? `Reply to ${handle}` : "Replies";
  if (subEl) subEl.textContent = sub ? sub.slice(0, 200) : "";

  const list = document.getElementById("feedReplyList");
  if (list) list.innerHTML = `<div class="feedReplyRowLoading" aria-hidden="true" style="padding:24px;text-align:center;color:rgba(232,238,247,0.4);font-size:13px;">Loading…</div>`;

  const input = document.getElementById("feedReplyInput");
  if (input) input.value = "";
  updateFeedReplyFormState();

  sheet.hidden = false;
  // Allow the layout to settle before triggering the transition.
  window.requestAnimationFrame(() => {
    sheet.setAttribute("aria-hidden", "false");
    if (input) {
      try { input.focus({ preventScroll: false }); } catch { input.focus(); }
    }
  });

  void loadFeedReplyList();
}

function closeFeedReplySheet() {
  const sheet = document.getElementById("feedReplySheet");
  if (!sheet) return;
  sheet.setAttribute("aria-hidden", "true");
  window.setTimeout(() => {
    sheet.hidden = true;
    _feedReplyContext = null;
  }, 220);
}

async function loadFeedReplyList() {
  const ctx = _feedReplyContext;
  if (!ctx) return;
  const list = document.getElementById("feedReplyList");
  if (!list) return;
  try {
    const params = new URLSearchParams();
    params.set("type", "replies");
    params.set("targetKind", ctx.targetKind);
    params.set("targetId", ctx.targetId);
    params.set("limit", "100");
    const data = await socialApi(`/api/social?${params.toString()}`);
    if (!_feedReplyContext || _feedReplyContext.targetId !== ctx.targetId) return;
    const replies = Array.isArray(data?.replies) ? data.replies : [];
    list.innerHTML = replies.map((r) => feedReplyRowHtml(r)).join("");
    // Update count in the underlying feed row optimistically.
    setFeedSocialStat(ctx.targetKind, ctx.targetId, { replyCount: replies.length });
    applyFeedSocialStatsToDom(document);
  } catch (e) {
    list.innerHTML = `<div style="padding:24px;text-align:center;color:rgba(255,100,130,0.85);font-size:13px;">${escapeHtml(e?.message || "Could not load replies.")}</div>`;
  }
}

function feedReplyRowHtml(reply) {
  const handle = String(reply?.username || "").trim();
  const safeHandle = escapeHtml(handle);
  const initials = (handle || "U").replace(/^@/, "").slice(0, 2).toUpperCase();
  const avatarRaw = String(reply?.avatar || "").trim();
  const avatarSrc = avatarRaw ? normalizeProfileAvatarForImg(avatarRaw) : "";
  const href = handle ? `#/u/${encodeURIComponent(handle)}` : "#";
  const ts = reply?.createdAt ? new Date(reply.createdAt).getTime() : 0;
  const when = ts ? relativeTime(ts) : "Just now";
  const body = escapeHtml(String(reply?.body || "").trim());
  const replyId = escapeHtml(String(reply?.id || ""));
  const isOwn = Boolean(
    reply?.userId &&
    authSession?.user?.id &&
    String(reply.userId) === String(authSession.user.id),
  );
  const deleteBtn = isOwn
    ? `<button type="button" class="feedReplyDelete" data-feed-reply-delete="${replyId}">Remove</button>`
    : "";
  return `
    <article class="feedReplyRow" data-feed-reply-id="${replyId}">
      <a class="feedReplyAvatar" href="${escapeHtml(href)}" data-route-link="user" aria-label="${handle ? `@${safeHandle} profile` : "Profile"}">
        ${avatarSrc
          ? `<img src="${escapeHtml(avatarSrc)}" alt="" width="36" height="36" decoding="async" loading="lazy" />`
          : `<span class="feedReplyAvatarFallback">${escapeHtml(initials)}</span>`}
      </a>
      <div>
        <div class="feedReplyMeta">
          <a class="feedReplyName" href="${escapeHtml(href)}" data-route-link="user">${handle ? `@${safeHandle}` : "A musician"}</a>
          <span aria-hidden="true">·</span>
          <span class="feedReplyWhen">${escapeHtml(when)}</span>
        </div>
        <p class="feedReplyBody">${body}</p>
        ${deleteBtn}
      </div>
    </article>`;
}

function updateFeedReplyFormState() {
  const input = document.getElementById("feedReplyInput");
  const submit = document.getElementById("feedReplySubmit");
  const counter = document.getElementById("feedReplyCount");
  if (!input || !submit || !counter) return;
  const len = (input.value || "").trim().length;
  const total = (input.value || "").length;
  submit.disabled = len === 0 || len > 280 || submit.dataset.busy === "1";
  counter.textContent = `${total} / 280`;
  counter.classList.toggle("isNear", total > 240 && total <= 280);
  counter.classList.toggle("isOver", total > 280);
}

async function submitFeedReply() {
  const ctx = _feedReplyContext;
  if (!ctx) return;
  const input = document.getElementById("feedReplyInput");
  const submit = document.getElementById("feedReplySubmit");
  if (!input || !submit) return;
  const body = String(input.value || "").trim();
  if (!body || body.length > 280) return;
  submit.dataset.busy = "1";
  submit.disabled = true;
  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({
        action: "reply",
        targetKind: ctx.targetKind,
        targetId: ctx.targetId,
        body,
      }),
    });
    if (data?.ok && data.reply) {
      const list = document.getElementById("feedReplyList");
      if (list) list.insertAdjacentHTML("beforeend", feedReplyRowHtml(data.reply));
      input.value = "";
      setFeedSocialStat(ctx.targetKind, ctx.targetId, {
        replyCount: Number(data.count) || (getFeedSocialStat(ctx.targetKind, ctx.targetId).replyCount + 1),
      });
      applyFeedSocialStatsToDom(document);
      try { haptic("light"); } catch {}
      // Scroll list to the new reply.
      if (list) list.scrollTop = list.scrollHeight;
    }
  } catch (e) {
    showToast(e?.message || "Could not post reply.");
  } finally {
    delete submit.dataset.busy;
    updateFeedReplyFormState();
  }
}

async function deleteFeedReply(replyId) {
  const ctx = _feedReplyContext;
  if (!ctx || !replyId) return;
  let ok = true;
  try { ok = window.confirm("Remove this reply?"); } catch { ok = true; }
  if (!ok) return;
  try {
    const data = await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({ action: "delete_reply", replyId }),
    });
    if (data?.ok) {
      const row = document.querySelector(`[data-feed-reply-id="${CSS.escape(String(replyId))}"]`);
      if (row) row.remove();
      const newCount = Number(data.count);
      if (Number.isFinite(newCount)) {
        setFeedSocialStat(ctx.targetKind, ctx.targetId, { replyCount: newCount });
        applyFeedSocialStatsToDom(document);
      }
    }
  } catch (e) {
    showToast(e?.message || "Could not remove reply.");
  }
}

function bindFeedReplySheetOnce() {
  if (_feedReplyBound) return;
  _feedReplyBound = true;
  const sheet = document.getElementById("feedReplySheet");
  const form = document.getElementById("feedReplyForm");
  const input = document.getElementById("feedReplyInput");
  const list = document.getElementById("feedReplyList");
  if (!sheet || !form || !input || !list) return;

  sheet.addEventListener("click", (e) => {
    if (e.target.closest("[data-feed-reply-dismiss]")) {
      e.preventDefault();
      closeFeedReplySheet();
    }
  });

  input.addEventListener("input", updateFeedReplyFormState);

  form.addEventListener("submit", (e) => {
    e.preventDefault();
    void submitFeedReply();
  });

  list.addEventListener("click", (e) => {
    const del = e.target.closest("[data-feed-reply-delete]");
    if (del) {
      e.preventDefault();
      void deleteFeedReply(del.getAttribute("data-feed-reply-delete"));
    }
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (sheet.getAttribute("aria-hidden") === "false") closeFeedReplySheet();
  });
}

async function handleFriendsWtfFollow(btn) {
  const targetUserId = String(btn.getAttribute("data-friends-follow") || "").trim();
  const handle = String(btn.getAttribute("data-friends-follow-handle") || "").trim();
  if (!targetUserId) return;
  if (!authSession?.user?.id || !getSupabaseAuthToken()) {
    showToast("Sign in to follow creators.");
    location.hash = "#/auth";
    return;
  }
  if (btn.dataset.followBusy === "1") return;
  btn.dataset.followBusy = "1";
  btn.disabled = true;
  const prevLabel = btn.textContent;
  btn.textContent = "Following…";
  try {
    haptic("light");
  } catch {}
  try {
    await socialApi("/api/social", {
      method: "POST",
      body: JSON.stringify({ action: "follow", targetUserId }),
    });
    btn.textContent = "Following";
    btn.classList.add("isFollowed");
    // Slide the row out, then refresh the feed so the new follow gets
    // pulled into the timeline and a fresh suggestion takes its place.
    const row = btn.closest(".friendsWtfRow");
    if (row) {
      row.classList.add("isLeaving");
      window.setTimeout(() => {
        row.remove();
        void refreshDiscoveryFollowingFeed({ force: true });
      }, 280);
    } else {
      void refreshDiscoveryFollowingFeed({ force: true });
    }
    showToast(handle ? `Following @${handle}.` : "Following creator.");
  } catch (e) {
    btn.textContent = prevLabel || "Follow";
    btn.disabled = false;
    delete btn.dataset.followBusy;
    showToast(e?.message || "Could not follow.");
  }
}

function renderDiscoveryFollowingEmpty(statusEl, title, text, actionHtml = "") {
  if (!statusEl) return;
  statusEl.hidden = false;
  statusEl.innerHTML = `
    <div class="discoveryEmptyWrap">
      <div class="discoveryEmptyArt">${discoveryEmptyIllustrationSvg()}</div>
      <p class="discoveryEmptyTitle">${escapeHtml(title)}</p>
      <p class="discoveryEmptyText">${escapeHtml(text)}</p>
      ${actionHtml}
    </div>`;
}

let _friendsRouteEnterToken = 0;
let _enterFriendsDebounce = 0;
let _friendsStatusComposePending = false;
let _friendsFeedAuthRetry = 0;
let _followingListCache = null;
let _followingListCacheAt = 0;
let _friendsFeedSnapshot = null;
const FOLLOWING_LIST_CACHE_MS = 45000;
const FRIENDS_FEED_SNAPSHOT_MS = 90000;
const FRIENDS_MIN_FETCH_GAP_MS = 30000;
const FRIENDS_FEED_SNAPSHOT_KEY = "nabad_friends_feed_snap_v2";

let _profileActSnapshot = null;
const PROFILE_ACT_SNAPSHOT_MS = 120000;
const PROFILE_ACT_MIN_FETCH_GAP_MS = 45000;
const PROFILE_ACT_SNAPSHOT_KEY = "nabad_profile_act_snap_v1";

function hydrateProfileActSnapshotFromStorage() {
  if (_profileActSnapshot) return;
  try {
    const raw = sessionStorage.getItem(PROFILE_ACT_SNAPSHOT_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (parsed?.at && Date.now() - parsed.at < PROFILE_ACT_SNAPSHOT_MS && parsed.html) {
      _profileActSnapshot = parsed;
    }
  } catch {}
}

function persistProfileActSnapshot() {
  if (!_profileActSnapshot) return;
  try {
    sessionStorage.setItem(PROFILE_ACT_SNAPSHOT_KEY, JSON.stringify(_profileActSnapshot));
  } catch {}
}

function invalidateProfileActivitiesCache() {
  _profileActSnapshot = null;
  try {
    sessionStorage.removeItem(PROFILE_ACT_SNAPSHOT_KEY);
  } catch {}
}
const FRIENDS_FEED_LIBRARY_USERS = 12;

function hydrateFriendsFeedSnapshotFromStorage() {
  if (_friendsFeedSnapshot) return;
  try {
    const raw = sessionStorage.getItem(FRIENDS_FEED_SNAPSHOT_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    if (parsed?.at && Date.now() - parsed.at < FRIENDS_FEED_SNAPSHOT_MS) {
      _friendsFeedSnapshot = parsed;
    }
  } catch {}
}

function persistFriendsFeedSnapshot() {
  if (!_friendsFeedSnapshot) return;
  try {
    sessionStorage.setItem(FRIENDS_FEED_SNAPSHOT_KEY, JSON.stringify(_friendsFeedSnapshot));
  } catch {}
}

function runFriendsRouteRefresh(token) {
  if (token !== _friendsRouteEnterToken) return;
  if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
  void refreshDiscoveryFollowingFeed();
}

function enterFriendsRoute() {
  const token = ++_friendsRouteEnterToken;
  bindFriendsPageOnce();
  wireFriendsComposeFabOnce();
  syncFollowingComposeUi();
  hydrateFriendsFeedSnapshotFromStorage();
  try {
    onEnterFriendsRoute();
  } catch {}
  void (async () => {
    if (token !== _friendsRouteEnterToken) return;
    await ensureFriendsFeedPrerequisites();
    if (token !== _friendsRouteEnterToken) return;
    if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
    runFriendsRouteRefresh(token);
  })();
  if (_friendsStatusComposePending) {
    if (_enterFriendsDebounce) clearTimeout(_enterFriendsDebounce);
    _enterFriendsDebounce = window.setTimeout(() => {
      _enterFriendsDebounce = 0;
      if (token !== _friendsRouteEnterToken) return;
      _friendsStatusComposePending = false;
      try { openFriendsComposeSheet(); } catch {}
    }, 80);
  }
}

function wireFriendsComposeFabOnce() {
  if (document.documentElement.dataset.friendsComposeFabWired) return;
  document.documentElement.dataset.friendsComposeFabWired = "1";
  document.addEventListener(
    "click",
    (e) => {
      const btn = e.target.closest("#friendsComposeOpenBtn");
      if (!btn) return;
      if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
      e.preventDefault();
      e.stopPropagation();
      haptic("light");
      const sheet = document.getElementById("friendsComposeSheet");
      if (sheet?.classList.contains("isOpen")) closeFriendsComposeSheet();
      else openFriendsComposeSheet();
    },
    true,
  );
}

async function refreshDiscoveryFollowingFeed(opts = {}) {
  const force = Boolean(opts.force);
  const gen = ++_discoveryFollowingGen;
  hydrateFriendsFeedSnapshotFromStorage();
  const statusEl = document.getElementById("discoveryFollowingStatus");
  const listEl = document.getElementById("discoveryFollowingList");
  if (!statusEl || !listEl) return;
  if (authSession?.user?.id) _friendsFeedAuthRetry = 0;

  const keepFeed = Boolean(_friendsOwnPostPin && listEl.querySelector(".followAct"));
  const snap = _friendsFeedSnapshot;
  const snapFresh =
    snap &&
    Date.now() - snap.at < FRIENDS_FEED_SNAPSHOT_MS &&
    snap.html &&
    !snap.html.includes("followAct--skel");
  if (snapFresh && !keepFeed) {
    listEl.classList.remove("isDiscoveryLoading");
    listEl.hidden = false;
    listEl.innerHTML = snap.html;
    statusEl.hidden = true;
    statusEl.textContent = "";
    if (Array.isArray(snap.tracks)) _discoveryFeedTracks = snap.tracks;
    try {
      syncDiscoveryPlayingHighlights();
    } catch {}
    applyFeedSocialStatsToDom(listEl);
    void hydrateFeedSocialStatsForFeed(listEl);
    if (!force && Date.now() - snap.at < FRIENDS_MIN_FETCH_GAP_MS) {
      return;
    }
  } else {
    listEl.classList.add("isDiscoveryLoading");
    listEl.hidden = false;
    if (!keepFeed) listEl.innerHTML = followingActivitySkeletonHtml();
    statusEl.hidden = true;
    statusEl.textContent = "";
  }

  const prereqReady = ensureFriendsFeedPrerequisites();
  if (!snapFresh) await prereqReady;
  else void prereqReady;
  if (gen !== _discoveryFollowingGen) return;
  const apiBlock = friendsFeedBlockedMessage();
  if (apiBlock) {
    listEl.classList.remove("isDiscoveryLoading");
    listEl.hidden = true;
    listEl.innerHTML = "";
    renderDiscoveryFollowingEmpty(
      statusEl,
      "Friends unavailable",
      apiBlock,
      `<button type="button" class="solid discoveryEmptyCta" id="friendsFeedRetryBtn">Try again</button>`,
    );
    const retry = document.getElementById("friendsFeedRetryBtn");
    if (retry && !retry.dataset.boundFriendsRetry) {
      retry.dataset.boundFriendsRetry = "1";
      retry.addEventListener("click", () => {
        try { haptic("light"); } catch {}
        lastPublicConfigError = "";
        lastPublicConfigStatus = 0;
        void loadPublicConfig().then(() => void refreshDiscoveryFollowingFeed());
      });
    }
    return;
  }

  if (!authSession?.user?.id) {
    const token = getSupabaseAuthToken();
    if (
      token &&
      String(document.body.getAttribute("data-route") || "") === "friends"
    ) {
      try {
        await refreshAuthStateFromSupabase();
      } catch {}
      if (authSession?.user?.id) {
        _friendsFeedAuthRetry = 0;
        /* fall through — session hydrated after login */
      } else if (_friendsFeedAuthRetry < 12) {
        _friendsFeedAuthRetry += 1;
        window.setTimeout(() => {
          if (gen !== _discoveryFollowingGen) return;
          if ((document.body.getAttribute("data-route") || "") !== "friends") return;
          void refreshDiscoveryFollowingFeed();
        }, 200);
        return;
      } else {
        _friendsFeedAuthRetry = 0;
        listEl.classList.remove("isDiscoveryLoading");
        listEl.hidden = true;
        listEl.innerHTML = "";
        renderDiscoveryFollowingEmpty(
          statusEl,
          "Sign in to see activity",
          "Follow musicians from Discover — their drops and remixes show up here.",
          `<a class="solid discoveryEmptyCta" href="#/profile">Sign in</a>`,
        );
        return;
      }
    } else {
      _friendsFeedAuthRetry = 0;
      listEl.classList.remove("isDiscoveryLoading");
      listEl.hidden = true;
      listEl.innerHTML = "";
      renderDiscoveryFollowingEmpty(
        statusEl,
        "Sign in to see activity",
        "Follow musicians from Discover — their drops and remixes show up here.",
        `<a class="solid discoveryEmptyCta" href="#/profile">Sign in</a>`,
      );
      return;
    }
  }

  try {
    const following = await fetchFollowingListForFeed();
    if (gen !== _discoveryFollowingGen) return;
    if (!following.length) {
      if (_friendsOwnPostPin) {
        if (gen !== _discoveryFollowingGen) return;
        const profMap = await fetchProfilesByUserIdsMap([String(authSession.user.id)]);
        listEl.classList.remove("isDiscoveryLoading");
        statusEl.hidden = true;
        listEl.hidden = false;
        listEl.innerHTML = followingStatusRowHtml(_friendsOwnPostPin, profMap, 0, { xstyle: true });
        return;
      }
      listEl.classList.remove("isDiscoveryLoading");
      listEl.hidden = true;
      listEl.innerHTML = "";
      const suggests = await fetchFollowingEmptySuggestCreators(3);
      const faces = suggests.length
        ? `<div class="followActEmptyFaces">${suggests
            .map((c) => {
              const href = `#/u/${encodeURIComponent(c.handle)}`;
              const av = c.avatar
                ? `<img src="${escapeHtml(c.avatar)}" alt="" width="44" height="44" decoding="async" />`
                : `<span class="followActEmptyFaceFallback">${escapeHtml(c.handle.slice(0, 2).toUpperCase())}</span>`;
              return `<a class="followActEmptyFace" href="${escapeHtml(href)}" data-route-link="user" title="@${escapeHtml(c.handle)}">${av}</a>`;
            })
            .join("")}</div>`
        : "";
      renderDiscoveryFollowingEmpty(
        statusEl,
        "Follow musicians to see activity",
        "Pick a few creators on Discover — new songs, remixes, and challenges land here.",
        `${faces}<a class="solid discoveryEmptyCta" href="#/discover" data-route-link="discover">Browse Discover</a>`,
      );
      return;
    }

    const libraryUserIds = following
      .slice(0, FRIENDS_FEED_LIBRARY_USERS)
      .map((creator) => String(creator?.userId || creator?.user_id || creator?.following_user_id || "").trim())
      .filter(Boolean);
    const [statusPosts, tracksByUser] = await Promise.all([
      fetchFollowingStatusPosts(40, following),
      supabaseFetchPublicLibraryForUserIds(libraryUserIds),
    ]);
    const tracksNested = libraryUserIds.map((userId) =>
      (tracksByUser.get(userId) || []).map((row) => ({ ...row, userId })),
    );
    if (gen !== _discoveryFollowingGen) return;

    const playable = tracksNested
      .flat()
      .filter((t) => {
        if (!String(t.url || "").trim()) return false;
        if (t.publicOnProfile === false) return false;
        return isDiscoverFeedActive(t);
      })
      .sort((a, b) => Number(b.ts || 0) - Number(a.ts || 0))
      .slice(0, 60);
    const profIds = [
      ...playable.map((t) => t.userId),
      ...statusPosts.map((p) => String(p?.userId || "").trim()).filter(Boolean),
    ];
    const profMap = await fetchProfilesByUserIdsMap(profIds);
    if (gen !== _discoveryFollowingGen) return;

    const playCountMap = await fetchDiscoverSongPlayCounts(playable.map((t) => t.id));
    if (gen !== _discoveryFollowingGen) return;
    for (const t of playable) {
      t.playCount = playCountMap.get(String(t.id || "")) || 0;
    }

    const feedItems = [
      ...statusPosts.map((post) => ({
        kind: "status",
        ts: new Date(post.createdAt || post.created_at || 0).getTime() || 0,
        post,
      })),
      ...playable.map((track) => ({
        kind: "music",
        ts: Number(track.ts || 0),
        track,
      })),
    ]
      .filter((row) => row.ts > 0 || row.kind === "status")
      .sort((a, b) => b.ts - a.ts);
    const mergedItems = mergeFriendsOwnPostPin(feedItems).slice(0, 80);

    listEl.classList.remove("isDiscoveryLoading");
    if (!mergedItems.length) {
      listEl.hidden = true;
      listEl.innerHTML = "";
      renderDiscoveryFollowingEmpty(
        statusEl,
        "Quiet for now",
        "Use Create in the tab bar to share an update, or wait for drops from people you follow.",
      );
      return;
    }

    statusEl.hidden = true;
    statusEl.textContent = "";
    _discoveryFeedTracks = playable.map((t) => discoveryTrackPlaybackMeta(t, profMap));
    listEl.hidden = false;
    const feedHtml = mergedItems
      .map((item, i) => (item.kind === "status"
        ? followingStatusRowHtml(item.post, profMap, i, { xstyle: true })
        : followingActivityRowHtml(item.track, profMap, i, { xstyle: true })))
      .join("");
    // X-style end-of-list "Who to follow": surface 3 musicians the viewer
    // doesn't already follow. Excludes self + everyone in their following
    // list so we never recommend somebody they already follow.
    const followedIds = following
      .map((f) => String(f?.userId || f?.user_id || f?.following_user_id || "").trim())
      .filter(Boolean);
    const suggestList = await fetchFollowingEmptySuggestCreators(3, followedIds);
    if (gen !== _discoveryFollowingGen) return;
    const wtfHtml = whoToFollowSectionHtml(suggestList);
    const fullHtml = `${feedHtml}${wtfHtml}`;
    listEl.innerHTML = fullHtml;
    _friendsFeedSnapshot = {
      at: Date.now(),
      html: fullHtml,
      tracks: _discoveryFeedTracks,
    };
    persistFriendsFeedSnapshot();
    // Apply any stats we already have from a previous fetch, then kick
    // off a fresh batch fetch to update counts and the liked-state.
    applyFeedSocialStatsToDom(listEl);
    void hydrateFeedSocialStatsForFeed(listEl);
    try {
      syncDiscoveryPlayingHighlights();
    } catch {}
  } catch (e) {
    if (gen !== _discoveryFollowingGen) return;
    listEl.classList.remove("isDiscoveryLoading");
    listEl.hidden = true;
    listEl.innerHTML = "";
    renderDiscoveryFollowingEmpty(
      statusEl,
      "Could not load Friends",
      socialApiErrorMessage(e),
      `<button type="button" class="solid discoveryEmptyCta" id="friendsFeedRetryBtn">Try again</button>`,
    );
    const retry = document.getElementById("friendsFeedRetryBtn");
    if (retry && !retry.dataset.boundFriendsRetry) {
      retry.dataset.boundFriendsRetry = "1";
      retry.addEventListener("click", () => {
        try { haptic("light"); } catch {}
        void refreshDiscoveryFollowingFeed();
      });
    }
  }
}

function bindDiscoveryDiscoverControls() {
  wireUserPublicFeedRowsOnce();
  if (_discoveryDiscoverBound) return;
  _discoveryDiscoverBound = true;
  const rfb = document.getElementById("discoveryRefreshBtn");
  if (rfb && !rfb.dataset.boundDiscoveryRefresh) {
    rfb.dataset.boundDiscoveryRefresh = "1";
    rfb.addEventListener("click", () => {
      haptic("light");
      rfb.classList.add("isRefreshing");
      void refreshDiscoverFeed().finally(() => {
        try { rfb.classList.remove("isRefreshing"); } catch {}
      });
    });
  }
  const dPane = document.getElementById("discoveryPaneDiscover");
  if (dPane && !dPane.dataset.boundDiscoverPane) {
    dPane.dataset.boundDiscoverPane = "1";
    wireTrackOptionsSheetOnce();
    dPane.addEventListener("click", (e) => {
      const challengePlay = e.target.closest("[data-challenge-entry-play]");
      if (challengePlay && document.getElementById("discoverChallengeSpotlight")?.contains(challengePlay)) {
        const raw = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-play");
        const title = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-title") || "Song";
        const art = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-art") || "";
        const by = decodeDiscoverDataAttr(challengePlay, "data-challenge-entry-by") || "";
        if (!raw) return;
        e.preventDefault();
        haptic("light");
        void playLibraryUrlOnPlayer(raw, title, art, { discoverFeed: true, openPlayer: false, discoverBy: by, playSource: publicPlaySourceFromEl(challengePlay) });
        return;
      }
      const menuBtn = e.target.closest("[data-discovery-open-sheet]");
      if (menuBtn && dPane.contains(menuBtn)) {
        e.preventDefault();
        e.stopPropagation();
        haptic("light");
        openDiscoverTrackSheetFromEl(menuBtn);
        return;
      }
      const cardWrap = e.target.closest(".discoveryFeedCardWrap");
      if (cardWrap && dPane.contains(cardWrap) && !e.target.closest("[data-discovery-open-sheet]")) {
        const pl = cardWrap.querySelector("[data-user-lib-play]");
        if (pl) {
          e.preventDefault();
          playDiscoverTarget(pl);
          return;
        }
      }
      const inline = e.target.closest("[data-discovery-inline-play]");
      if (inline && dPane.contains(inline)) {
        e.preventDefault();
        playDiscoverTarget(inline);
        return;
      }
      const pl = e.target.closest("[data-user-lib-play]");
      if (!pl || !dPane.contains(pl)) return;
      e.preventDefault();
      playDiscoverTarget(pl);
    });
  }
}

function bindFriendsPageOnce() {
  wireUserPublicFeedRowsOnce();
  bindFollowingComposeOnce();
  wireFriendsComposeSheetOnce();
  wireCreateChooserSheetOnce();
  wireFriendsComposeFabOnce();
  if (!_friendsStatusMenuDocBound) {
    _friendsStatusMenuDocBound = true;
    document.addEventListener("click", (e) => {
      if (String(document.body.getAttribute("data-route") || "") !== "friends") return;
      if (e.target.closest(".followActMenuWrap")) return;
      closeAllFollowStatusMenus();
    });
  }
  if (_friendsPageBound) return;
  _friendsPageBound = true;
  const friendsPage = document.getElementById("friendsPage");
  if (friendsPage && !friendsPage.dataset.boundFriendsPage) {
    friendsPage.dataset.boundFriendsPage = "1";
    wireTrackOptionsSheetOnce();
    friendsPage.addEventListener("click", (e) => {
      const menuBtn = e.target.closest("[data-follow-status-menu]");
      if (menuBtn && friendsPage.contains(menuBtn)) {
        e.preventDefault();
        e.stopPropagation();
        const row = menuBtn.closest(".followAct--status");
        const menu = row?.querySelector(".followActMenu");
        const wasOpen = row?.classList.contains("followAct--statusMenuOpen");
        closeAllFollowStatusMenus();
        if (!wasOpen && row && menu) {
          row.classList.add("followAct--statusMenuOpen");
          menu.hidden = false;
          menuBtn.setAttribute("aria-expanded", "true");
        }
        return;
      }
      const delBtn = e.target.closest("[data-follow-status-delete]");
      if (delBtn && friendsPage.contains(delBtn)) {
        e.preventDefault();
        e.stopPropagation();
        closeAllFollowStatusMenus();
        void deleteFollowingStatusPost(delBtn.getAttribute("data-follow-status-delete"));
        return;
      }
      const followBtn = e.target.closest("[data-friends-follow]");
      if (followBtn && friendsPage.contains(followBtn)) {
        e.preventDefault();
        e.stopPropagation();
        void handleFriendsWtfFollow(followBtn);
        return;
      }
      const actBtn = e.target.closest("[data-friends-act]");
      if (actBtn && friendsPage.contains(actBtn)) {
        const kind = actBtn.getAttribute("data-friends-act");
        if (kind === "plays") return;
        e.preventDefault();
        e.stopPropagation();
        if (kind === "like") void handleFeedLikeTap(actBtn);
        else if (kind === "reply") void openFeedReplySheetFromButton(actBtn);
        return;
      }
      if (e.target.closest(".followActAvatar")) return;
      const pl = e.target.closest("[data-user-lib-play], .followActMedia, .followActQuoteCard, .followActUserLink");
      if (pl?.classList?.contains?.("followActUserLink")) return;
      if (!pl || !friendsPage.contains(pl)) return;
      e.preventDefault();
      if (pl.classList.contains("followActMedia") || pl.classList.contains("followActQuoteCard") || pl.hasAttribute("data-user-lib-play")) {
        playDiscoverTarget(pl);
      }
    });
  }
}

