async function waitForCapPlugin(name, maxMs = 4000) {
  const cap = window?.Capacitor;
  if (!cap) return null;
  if (!cap.isNativePlatform?.()) return cap.Plugins?.[name] || null;
  const deadline = Date.now() + maxMs;
  while (Date.now() < deadline) {
    const plugin = cap.Plugins?.[name];
    if (plugin?.get || plugin?.set) return plugin;
    await new Promise((r) => setTimeout(r, 40));
  }
  return cap.Plugins?.[name] || null;
}

function decodeJwtPayload(token) {
  try {
    const part = String(token || "").split(".")[1];
    if (!part) return null;
    const pad = part.length % 4 === 0 ? part : `${part}${"=".repeat(4 - (part.length % 4))}`;
    const json = atob(pad.replace(/-/g, "+").replace(/_/g, "/"));
    return JSON.parse(json);
  } catch {
    return null;
  }
}

function hydrateAuthUserFromJwt(sess) {
  if (!sess?.access_token) return sess;
  const u = sess.user && typeof sess.user === "object" ? { ...sess.user } : {};
  if (u.id) return { ...sess, user: u };
  const p = decodeJwtPayload(sess.access_token);
  const sub = String(p?.sub || "").trim();
  if (!sub) return sess;
  return {
    ...sess,
    user: {
      ...u,
      id: sub,
      email: u.email || String(p?.email || "").trim(),
    },
  };
}

function ensureAuthSessionUserFromToken() {
  if (authSession?.user?.id) return authSession;
  const tok = getSupabaseAuthToken();
  if (!tok) return authSession;
  const hydrated = normalizeAuthSession({ ...(authSession || {}), access_token: tok });
  if (hydrated) authSession = hydrated;
  return authSession;
}

